rocom_list = {
    "迪莫":[120, 80, 80, 105, 105, 92, ['光'], '最好的伙伴', [], '这是关于勇气的故事，它很脆弱却也不曾退缩；这是关于梦想的故事，梦很简单却也执着。这就是我，迪莫。'],
    "喵喵":[65, 66, 66, 49, 91, 33, ['草'], '氧循环', [], '喜欢阳光，喜欢新鲜的空气，会摇晃尾巴，受到惊吓会快速逃跑。虽然很胆小，但是也有时候非常调皮。'],
    "喵呜":[86, 87, 87, 65, 121, 44, ['草'], '氧循环', [], '爱在泉水边嬉戏，是喵喵的进化型，芭蕉叶状的尾巴变成了两条。胆量变大了，会经常吐舌头挑衅对手。'],
    "魔力猫":[108, 109, 109, 81, 151, 55, ['草'], '氧循环', [], '普遍性情温和，体型巨大，据说深吸一口气能呼出将洛克都吹走的狂风，但通常情况下举止动作十分轻柔。长了三条锋利的尾巴，经常会用身体冲撞碾压对手。'],
    "火花":[70, 84, 37, 56, 43, 78, ['火'], '助燃', [], '像一团迸发的小火花，坦诚炙热，生性勇敢无畏。能熟练运用火元素，偶尔有点冒失，是值得信赖的伙伴。'],
    "焰火":[93, 111, 49, 75, 58, 104, ['火'], '助燃', [], '长出了一对大翅膀，但似乎并不是用来飞行的。能用双手释放出更加强力的火焰，但不太熟练。'],
    "火神":[117, 139, 61, 94, 72, 130, ['火'], '助燃', [], '强大的火焰之灵，只是靠近它就能够感受到温度的急剧变化。如果没有脖子上的项圈，它的火焰可能会暴走。“在磨练中成长，在烈火中重生，用意志在战斗，用生命在燃烧，永远的火神”。'],
    "水蓝蓝":[75, 35, 76, 56, 79, 51, ['水'], '浸润', [], '漂浮在水面上的精灵，没事吐个泡泡，头顶有一个红色的蝴蝶结。不在水中的时候，身体上也覆盖了一层液体薄膜。'],
    "波波拉":[100, 46, 102, 75, 106, 68, ['水'], '浸润', [], '在水中自如地游动，头上的触角可以感受水中的变化，总是带着一颗球一样的东西。身旁环绕着特殊的水元素，水元素凝结体中蕴含魔法能量的波动。'],
    "水灵":[125, 58, 127, 94, 132, 85, ['水'], '浸润', [], '将刚刚孕育的胚胎顶在头上，胚胎由特殊水元素包裹着。能将身边的水元素汇集在一起喷射出去，产生强大的冲击力。“无论是云中落下的一滴水，还是湖面中微风吹起的一道涟漪，都有她的身影”。'],
    "鸭吉吉":[136, 95, 35, 55, 45, 105, ['普通'], '挺起胸脯', [], '拥有蓬松的被毛，非常柔软。似乎很讨厌肢体接触，抗拒被抚摸。非常聪慧的物种，对环境中与众不同的东西十分敏感，尤其对于闪光的物体和新奇的事物格外感兴趣。'],
    "板板壳":[67, 28, 72, 64, 81, 45, ['水'], '缩壳', [], '平时看似懒懒的，感到危险时，柔软的身体会迅速缩回壳里。柔韧的尾巴看起来像海草，偶尔会被饥饿的水生精灵咬一口。'],
    "咔咔壳":[90, 37, 96, 85, 107, 60, ['水'], '缩壳', [], '很少再缩进壳里，即使遇到危险也会勇敢面对。甲壳内一部分是空气，一部分是水，通过喷嘴来调节重量从而在水中下潜和上浮。'],
    "水泡壳":[112, 46, 120, 107, 134, 75, ['水'], '缩壳', [], '进化之后体重增长到原来的三倍多，前肢的力量也变得十分发达。前面有坚硬的尖角，背后有甲壳和水炮的泵口，是像堡垒一样可靠的存在。'],
    "锥尾羊":[67, 66, 29, 72, 49, 66, ['幽'], '碰瓷', [], '白色的毛十分蓬松，脚掌柔软，移动时悄无声息，因此很擅长藏身草原与坡地。它性格安静，同类之间常用轻轻顶犄角的方式交流。'],
    "铃兰羊":[89, 89, 39, 96, 65, 88, ['幽'], '碰瓷', [], '白天会懒洋洋地趴在草原上休息，主要在早晨和黄昏行动，一般会脱离种群独自生活。跳跃力惊人，在山坡上如履平地，从100米的高度一跃而下也没事。'],
    "花影羚羊":[112, 111, 48, 120, 81, 110, ['幽', '恶'], '碰瓷', [], '进化后，分叉的角更为锋利，中间盛开一朵蓝色花朵，花瓣能体现它们的身体状态，疲劳时，花瓣会略微下垂。花朵在夜晚能发出怪异的微光，能够迷惑对手。'],
    "雪绒鸟":[54, 77, 33, 65, 44, 69, ['翼'], '顺风', [], '冬天诞生的小鸟精灵，常把身体缩成球状减少散热。喜欢用幼嫩的喙啄刚落地的新雪，既是食用也是玩耍。'],
    "冬羽雀":[72, 103, 44, 86, 59, 92, ['翼'], '顺风', [], '体型又小又圆，眼睛周围生长着一层柔软绒毛。羽绒非常厚，为了抵御寒冷的冬夜，常与同伴挤在一起栖息。'],
    "岚鸟":[90, 128, 55, 108, 74, 115, ['翼'], '顺风', [], '眼神锐利，有着绅士般冷静而又端庄的非凡气质，让它在贵族当中颇有人气。胸腹绒羽形成稳定的隔热层，能在强风中维持体温，拥有较强的耐力。'],
    "小灵菇":[67, 59, 59, 62, 82, 45, ['幽'], '毒蘑菇', [], '可能在任何潮湿的阴冷角落出现，看到蓝色荧光不要贸然接近。吸食其他生物的情绪作为养分，吃饱后会发出轻轻的叹气声。'],
    "幻灵菇":[89, 79, 79, 83, 109, 60, ['幽', '草'], '毒蘑菇', [], '头顶的触角比隐藏在伞盖下的面目更能够表达出心情，悄无声息地飘来飘去，通常出现在后半夜。在森林深处大量聚集，散发着淡淡荧光，会吸收周围植物和小型动物的情绪。'],
    "幻影灵菇":[111, 98, 98, 103, 136, 75, ['幽', '草'], '毒蘑菇', [], '仅仅看到它触角上闪烁的荧光就会头痛难耐，对其研究很难有进展。没有生命迹象但是可以自如活动，无法判定是植物还是生物，唯独颈间圆环中似乎蕴含强大生命力。'],
    "石肤蜥":[69, 54, 53, 65, 45, 57, ['地'], '刺肤', [], '常在半山腰处被发现，独立生活，会收集细小的石头筑巢。背上的石头是体内生长出来的一种分泌物，喜欢钻到石头堆里蹭背，可以把背上的石头打磨得更加锋利。'],
    "石刺蜥":[92, 72, 71, 87, 60, 76, ['地'], '刺肤', [], '背上的石头似乎会与身上的棘刺融为一体，成为自己的武器。石头会周期性脱落，脱落下来的石头苍白易碎，捏一下就会粉碎成细砂状。'],
    "石冠王蜥":[115, 89, 89, 109, 75, 95, ['地'], '刺肤', [], '普遍性情暴躁，攻击性强，会发射岩石来划清自己的地盘。它背上石头与身体融合的原理至今仍是研究协会重要的研究课题。'],
    "布是石":[72, 81, 29, 95, 90, 42, ['地'], '地脉', [], '如果感觉岩石的缝隙中有目光注视着你，那很可能就是布是石。身体非常坚硬，喜欢成群结队地斜坡上滚下来，也许只有它们能感受这种快乐吧。'],
    "布是岩":[96, 108, 39, 127, 120, 56, ['地'], '地脉', [], '脑袋部分的坚硬度接近基岩，普通的岩石对它来说就像泥土一样柔软。它的头好像完全感觉不到疼，受到击打很久之后才能明白刚才发生了什么。'],
    "布克棱岩":[120, 135, 49, 159, 150, 70, ['地'], '地脉', [], '颇具威慑力的精灵，身形巨大，不经常远离驻地。看上去很重，但其实身体的主要重量都集中在头和手上的岩石部分。'],
    "恶魔叮":[86, 112, 44, 58, 43, 84, ['恶', '翼'], '渴求', [], '身体里似乎装满了坏心思，很轻松就能从试图抓住它的洛克手中挣脱。会三五成群地从洛克手上抢走东西，把东西丢下之后嘻嘻哈哈地飞走。如果惹怒它们的话，会气呼呼地撞向洛克。'],
    "叮叮恶魔":[108, 140, 55, 73, 54, 105, ['恶', '翼'], '渴求', [], '一直在思考如何恶作剧，还会每天进行吓人的练习。总是歪嘴笑着，一副玩世不恭的样子，其实非常害怕失去别人的注意力。非常重视诺言，会坚定地完成自己的约定。'],
    "毛毛":[32, 28, 28, 40, 40, 60, ['虫', '萌'], '化茧', [], '喜欢藏在地下，靠形似耳朵的触角感知周围环境。几乎观察不到它们进食行为，吃很少的东西就能存活很久。'],
    "爬爬":[42, 37, 37, 53, 53, 80, ['虫', '萌'], '化茧', [], '外壳硬化，缩腹在各种物体的表面爬行。背面艳丽的斑点看似有毒，实际上是鳞翅根。'],
    "化蝶":[53, 46, 46, 66, 66, 100, ['虫', '萌'], '化茧', [], '极其聪慧的种族，大脑占去整个身体的三分之二。翅膀有力，充满魔力的鳞粉形成了翅膀上的花纹，用以迷惑其他精灵。'],
    "幽影树":[111, 96, 96, 65, 123, 80, ['幽', '草'], '小偷小摸', [], '左手和右手似乎有独自的想法，在黑暗中看起来就像三只精灵。虽然伪装拙劣到谁都能看穿的程度，但依旧喜欢伪装成普通树木的样子，跟在洛克身后，但是对洛克并没有恶意。'],
    "小鼠獭":[73, 57, 57, 60, 60, 48, ['普通', '水'], '保守派', [], '总是在啃着什么，包括自己的手和尾巴。扒开小鼠獭的嘴巴仔细观察也找不到牙，牙床嫩嫩的，还没有牙的痕迹。'],
    "燕尾獭":[97, 77, 77, 81, 81, 64, ['普通', '水'], '保守派', [], '牙齿锋利，非常喜欢啃一些坚硬的木头。手掌心非常坚硬粗糙，常看到它们用手在脸上搓来搓去，并不是在洗脸，而是在用掌心磨牙齿。'],
    "卷胡巨獭":[121, 96, 96, 101, 101, 80, ['普通', '水'], '保守派', [], '对外表有蛮高的追求，除了磨牙的习惯之外，体内分泌的油脂会被用来保养胡须。蓬松的胡须和锋利的牙齿代表其在族群中的地位，部分獭会去寻找枯草装作假胡子戴着。普遍不喜欢和洛克亲近。'],
    "矿晶虫":[79, 77, 81, 102, 75, 52, ['光', '地'], '偏振', [], '喜欢攀附于潮湿的岩层，以土壤中的矿粒为食，常被用作衡量矿产资源丰富度的标志。身上的晶体可以将细小的光线通过折射放大数倍，四只矿晶虫便能照亮一整个矿洞，是备受矿工喜爱的精灵。'],
    "晶石蜗":[99, 96, 101, 128, 94, 65, ['光', '地'], '偏振', [], '在资源丰富的矿洞中能遇见的罕见蜗类，周身的矿石与斑纹会因摄入矿物类型的不同，而呈现出不同的色彩。进食时，它会直接吞下成块矿石，并通过特殊的消化结构，将其转化并沉积为自身躯体的一部分。'],
    "奇丽草":[67, 69, 69, 73, 57, 48, ['草'], '养分重吸收', [], '头顶着花苞爬着前进，总会朝着太阳光的方向。花苞里面似乎孕育着什么，要是长期照不到太阳，花苞就会萎缩。'],
    "奇丽叶":[90, 92, 92, 97, 76, 64, ['草'], '养分重吸收', [], '头顶的花苞十分巨大，花苞成长速度已经超过身体，头部上方是视野盲区，由身体下面五个足状的突起维持平衡。'],
    "奇丽花":[112, 115, 115, 121, 95, 80, ['草'], '养分重吸收', [], '巨大的花朵盛开了，花瓣像是一顶遮阳帽，粗大的花蕊像触角一样，花朵很好闻，有类似柑橘的香甜气味，对小型精灵有强烈吸引力。'],
    "丢丢":[44, 45, 12, 49, 40, 78, ['草'], '诈死', [], '有看到什么都会去舔一下试试看的习惯，经常忘记把舌头收回去。双眼对强光非常敏感，白天会老老实实躲在室内或者阴凉的地方。'],
    "卡卡虫":[59, 60, 16, 65, 53, 104, ['草'], '诈死', [], '用四只吸盘在任何地形快速地移动，静止不动地时候很难分辨。尾巴牢牢抓着植物的茎，没事就会拿下来舔，它的唾液似乎会让果实越变越硬。'],
    "卡瓦重":[74, 75, 20, 81, 67, 130, ['草'], '诈死', [], '手里拿的是生长着果实的枝条，既是武器也是乐器，需要时还能解解嘴馋。战斗像舞蹈一样，用细长灵活的舌头和尾巴表演，让人眼花缭乱。'],
    "护主犬":[68, 103, 37, 81, 66, 96, ['火'], '专注力', [], '时刻保持着警觉，任何危险都无法逃过他的眼睛。虽然身形小巧，但面对无论多么凶猛庞大的敌人都会勇敢地燃起斗志。'],
    "音速犬":[85, 128, 46, 101, 82, 120, ['火'], '专注力', [], '昂起斗志时，冠毛和尾巴会像熊熊燃烧的火焰一样摇曳。身上的围巾蕴含魔法能量，似乎有增强火元素的效果。'],
    "绿耳松鼠":[69, 50, 47, 67, 52, 48, ['普通'], '囤积', [], '能靠有力的尾巴弹跳，如果摔倒了，要花一阵子才能重新靠尾巴站立，有研究猜测它们足部功能有所退化，尾部功能非常发达，部分取代了双脚的作用。'],
    "抱枕松鼠":[92, 67, 63, 89, 70, 64, ['普通'], '囤积', [], '骑着自己的尾巴，已经不需要靠双脚走路。偶尔把头埋进身体，看上去像一颗巨大的果实。'],
    "蹦床松鼠":[114, 84, 79, 111, 87, 80, ['普通'], '囤积', [], '尾巴的力量非常强，巨大的尾部并不是蓬松的，内部有着强健的肌肉，实心并且富有弹性。可以用尾巴把自己弹射到三层楼那么高的地方。'],
    "嘟嘟煲":[110, 29, 82, 71, 83, 84, ['毒'], '复方汤剂', [], '体内的粘液有毒性，总是黏糊糊的，一旦沾上很难洗掉，粘液的沸点十分低，常处于沸腾状态。'],
    "嘟嘟锅":[137, 36, 102, 89, 104, 105, ['毒'], '复方汤剂', [], '一直在咕嘟咕嘟，分不清是因为沸腾导致，还是在喋喋不休。似乎有意四处散播谣言，说自己是炼金教室里大炼金釜的嫡系子嗣，研究人员在进行研究观测的时候每天要听五十遍它们讲的辉煌家史。'],
    "小灵面":[55, 30, 72, 59, 81, 69, ['幽'], '惊吓', [], '面具似乎可以摘下，进食的时候会避开所有生物。一层闪着荧光的神秘物质覆盖着身体，内部可能是液体。'],
    "暗影灵面":[74, 40, 96, 78, 108, 92, ['幽'], '惊吓', [], '被两团冷火环绕着，从头到脚都充满了谜团。进食之后重量也毫不增加，被它面具下的嘴吞下的食物仿佛消失了一样。'],
    "幽冥眼":[92, 50, 120, 98, 135, 115, ['幽'], '惊吓', [], '传说幽冥眼一族在生命终结的时候能窥见生命与宇宙的奥秘。对灵魂与星辰抱有极其虔诚的信仰，面具上刻着的眼睛形状图腾似乎象征着种族的信仰。'],
    "梦游":[90, 40, 106, 60, 74, 92, ['幽'], '做噩梦', [], '不吃不喝，大部分时间都在睡觉的奇怪生物，常呆在旧衣服堆里。喜欢群居生活，如果太长时间没有感受到其他生物的活动痕迹，会变得非常怨恨和暴躁。'],
    "梦悠悠":[113, 50, 133, 75, 93, 115, ['幽'], '做噩梦', [], '被遗忘的旧睡衣，因为孤单和思念而死，死后变成了幽灵。明明是毛绒绒的，但是体表温度极低，摸起来很凉，即使一直抱着它，它也很难变暖。'],
    "兽花蕾":[70, 79, 82, 70, 97, 115, ['光', '草'], '稀兽花宝', [], '稀兽花种的幼年形态，非常轻，会随风而动，身后有像翅膀一样的苞片，苞片上有特殊的薄膜，可以起到防风防水的效果，保护它们健康成长。'],
    "伏地兽":[95, 56, 25, 70, 41, 51, ['普通'], '壮胆', [], '柔韧的吻部十分有弹性，没有牙齿，用舌头和吻部配合嘬取食物。每天吃几十只蚂蚁就可以存活，能量消耗很小，多数时间在睡觉。'],
    "贪食鼹":[126, 74, 33, 94, 54, 68, ['普通'], '壮胆', [], '吻部变得坚硬，形状如同吸管，舌头又长又黏。没有嗅觉器官，通过舌头来感知气味，经常舔舐各种味道刺激的东西。'],
    "巨噬针鼹":[158, 93, 41, 117, 68, 85, ['普通'], '壮胆', [], '体表坚硬的鬃毛能够防御风吹日晒和敌人的攻击。长舌灵活而柔韧，能够绊倒猎物或者缠绕颈部使其窒息，吻部如同长矛一般刺穿猎物的要害，甚至可以击穿岩石。'],
    "蹦蹦种子":[60, 64, 66, 44, 63, 51, ['草', '毒'], '生物碱', [], '总是蹦蹦跳跳的，会用滚动的方式攻击。对温度和湿度都很敏感，但就算冷得发抖也不抱团取暖。'],
    "蹦蹦草":[80, 85, 88, 59, 84, 68, ['草', '毒'], '生物碱', [], '挥舞着长满刺的双手跳来跳去，要小心地接近。在太阳光下变得格外兴奋，情绪波动时头顶的花苞有可能突然绽放。'],
    "蹦蹦花":[100, 107, 110, 73, 105, 85, ['草', '毒'], '生物碱', [], '休息的时候会把脚插入地下一动不动，但似乎随时能够进入战斗状态。头上的花不允许任何人触碰，那似乎是它生命力量的来源。'],
    "电咩咩":[47, 49, 49, 55, 57, 75, ['电'], '快充', [], '整个咩咩非常蓬松，每一根蓬松的毛都带电，稍微靠近它就要被静电“哔哩”一下。释放能量之后会进入低电量状态，低电量时会没精打采并吃很多。'],
    "粉咩咩":[62, 66, 66, 73, 76, 100, ['电'], '快充', [], '经常看到它们聚在一起胡乱放电，放电的时候会跳奇怪的舞蹈，十分开心的样子。如果埋进它们的毛里猛吸一口，被电很惨同时闻到糊糊的怪味。'],
    "电球咩咩":[78, 82, 82, 91, 95, 125, ['电'], '快充', [], '头顶的毛团会定期脱落并瞬间萌发出新的一团。当遇到危险的时候，电球咩咩会快速脱落掉头顶毛团，以达到吸引敌人注意力的效果。'],
    "蒲公英":[89, 99, 94, 103, 78, 52, ['草', '萌'], '勇敢', [], '喜欢阳光，可爱的圆形精灵，三只一起在草丛中随风飘动。风吹到哪就会飞到哪，总是无忧无虑的。'],
    "蒲公英娃娃":[111, 123, 117, 129, 97, 65, ['草', '萌'], '勇敢', [], '三个可爱的小家伙簇拥着一团轻盈的绒球，绒球的内部构造不得而知。协同发力的话，能够随心所欲地借助风力飞往任何地方。'],
    "伊贝儿":[85, 73, 71, 76, 76, 72, ['草'], '腐植循环', [], '它头顶长着一团蓬松的绿色苔藓，压低身体时能很好地融入草丛，几乎难以分辨。苔藓本身不疏水，一旦沾到水就会迅速吸收并变得沉重，让它行动迟缓甚至走不动，只能停在原地等待自然风干。它的身体像果冻一样具有弹性，可拉伸变形。'],
    "伊贝粉粉":[106, 91, 89, 95, 95, 90, ['草'], '腐植循环', [], '苔藓常把眼睛遮住，因此它对细微动作的反应显得迟钝。若有洛克替它把苔藓梳理开，它会明显变得开心。进食后体型会短暂膨大一圈，随后再慢慢恢复原状。'],
    "白发懒人":[86, 94, 38, 81, 66, 45, ['普通'], '慢热型', [], '一直闭着眼睛在睡觉，即使是醒了也看不出来。在它睡着的时候也能对听到的声音有所反应，仿佛是个熟练的梦游者。'],
    "动力猿":[115, 125, 51, 108, 88, 60, ['普通', '武'], '慢热型', [], '有一半的时间在睡觉，极少保持清醒，清醒时精力极其旺盛。会使劲捶打胸口努力让自己变得清醒，但是卖力地运动过后睡得更沉了。'],
    "瞌睡王":[144, 157, 64, 135, 110, 75, ['普通', '武'], '慢热型', [], '比较难找到它的眼睛，主要靠鼾声来判断它是不是醒着。即使危险就在面前也能睡得香香的，或许是强大的体格给了它这样做的底气。'],
    "海盔虫":[71, 25, 59, 46, 66, 60, ['水', '毒'], '溶解扩散', [], '它静止时像不起眼的礁石，让人很难判断这是不是生物。它以底栖方式缓慢移动，活动量与食物多少直接相关，食物少时一天可能只挪动一点点。棘刺间分布感光细胞，使它对强光十分敏感，常本能地躲向阴影。'],
    "刺盔虫":[94, 33, 79, 61, 88, 80, ['水', '毒'], '溶解扩散', [], '刺上会卡着贝壳，木片，海藻。长长的棘刺有大量感光细胞，对光线非常敏感，具有负趋光性，为了逃避光线会在日间抓着各种东西为自己遮挡光线。食物充足时移动距离也会稍微变大。'],
    "千棘盔":[118, 41, 99, 76, 111, 100, ['水', '毒'], '溶解扩散', [], '平时它仍行动迟缓。但遇险时能短暂加速，脱离光照与威胁区域。受到轻微触碰时，棘刺会迅速聚合，并指向接触点，棘端的毒囊能造成刺痛与轻微麻木。'],
    "菊花梨":[106, 49, 116, 77, 115, 60, ['萌'], '无忧无虑', [], '看起来像梨，闻起来像梨，尝起来味道也像梨。睡觉的时候会把身体藏在泥巴里，只把花朵留在地面上。小黄蜂想要来授粉的话它会非常苦恼。'],
    "小星光":[60, 81, 85, 72, 88, 108, ['电'], '电流刺激', [], '草原晴天的微风里，常传来细碎噼啪——那是小星光在甩鬃毛，它们似乎总是处于炸毛的状态，其实是毛发里的电流导致的。它们从来不怕打雷，长长的尾巴能起到导电的作用，被雷劈中也不会受伤。'],
    "星光狮":[75, 101, 106, 90, 110, 135, ['电'], '电流刺激', [], '头顶的晶体是身体的一部分，里面似乎蕴含着无尽的能量。从晶体中发射能量攻击对手，吃饱睡好的情况下发射的能量炮能炸掉整个聆风塔地。'],
    "一窝蜂":[87, 32, 29, 27, 27, 26, ['虫', '翼'], '虫群鼓舞', [], '悬浮着的蜂巢就像身体的一部分一样灵活运动。可能是受某种信息素或者魔法影响，总会默契地做出协同的动作。'],
    "黄蜂后":[116, 43, 39, 36, 36, 35, ['虫', '翼'], '虫群鼓舞', [], '在蜂后的下半身周围有能量波动，推测是用来建立两只小蜂的联系。战斗时，蜂后的两眼会变成红色，针刺也会变得锋利无比。'],
    "女王蜂":[145, 50, 45, 42, 42, 40, ['虫', '翼'], '虫群鼓舞', [], '穿着披风、戴着王冠的蜂后，总是带着它的两个小侍卫。高雅的女王形象令人印象深刻，它的外形曾经是许多服装设计的灵感。'],
    "小夜":[60, 69, 63, 62, 51, 69, ['恶'], '嫁祸', [], '身手敏捷的小猫，擅长在雾气中隐藏身形，也可以幻化成其他物体。常常以惊讶和恐惧为食，消化后会散发出一种奇怪的味道。'],
    "紫夜":[80, 92, 84, 83, 68, 92, ['恶'], '嫁祸', [], '经常四处游历，偶尔幻化成其他精灵的样子之后偷偷潜入其他族群中，猜测是为了锻炼自己的幻化能力。通常情况下喜欢独自生活。'],
    "朔夜伊芙":[100, 115, 105, 104, 85, 115, ['恶'], '嫁祸', [], '喜欢在远处观察其他精灵的活动，有时会故意制造幻象来测试目标的反应。几乎不与同类接触，有些排斥社交，意外的是，被亲近的洛克抚摸的话耳朵尖会发光。'],
    "乖乖鹄":[75, 57, 52, 83, 58, 69, ['翼', '水'], '洁癖', [], '羽毛有很好的疏水性，可以毫不费力地浮在水面上，浮着的时候怔怔地看着水面，并不是在发呆，而是在检查自己的美丽，小小的乖乖鹄很早就已经意识到了美丽与优雅的重要性。'],
    "蓝珠天鹅":[100, 76, 69, 110, 78, 92, ['翼', '水'], '洁癖', [], '有强烈美意识的种族，时常梳理羽毛，用珍珠来打扮自己。优雅的举止和良好的外表是向同伴传递自身健康强壮的信号，拥有的珍珠数量也决定了自身在种群中的地位。'],
    "翠顶夫人":[125, 95, 86, 138, 97, 115, ['翼', '水'], '洁癖', [], '柔弱温顺，羽毛软而蓬松。过于专注梳理羽毛可能会迷路，意识到迷路的时候通常已经游到了完全不认识的环境里。不过总能保持优雅淡定，似乎永远不会慌张惊恐。这或许是夫人为自己制定的礼仪规范。'],
    "黑羽夫人":[132, 93, 87, 130, 90, 120, ['翼', '恶'], '贪婪', [], '天鹅精灵中罕见的独居分支，对社交并不热衷。羽毛长而卷翘，摸起来有些刺手，似乎并不符合种族中普遍的审美，但自信令她看起来非常优雅。'],
    "锤头鹳":[111, 67, 65, 91, 72, 105, ['翼', '水'], '快锤', [], '三三两两地站在建筑的高处，有些神秘，被认为是王国的守护者。洛克靠近时，会发出尖锐刺耳的声音，头部奇怪的形状为工具设计提供了设计灵感。'],
    "绿草精灵":[79, 35, 89, 87, 111, 72, ['草', '幻'], '木桶戏法', [], '在森林里挥舞着手中的木棍，好像是在做施放巫术的练习。偶尔会和帽子交谈，晒太阳的时候可能会发出诡异的笑声。'],
    "魔草巫灵":[99, 43, 112, 109, 139, 90, ['草', '幻'], '木桶戏法', [], '守护着森林的小巫师，头上的帽子似乎已经跟随它多年了。帽子的两侧是它树叶状的耳朵，能听到树木之间的对话。'],
    "记忆石":[112, 108, 97, 141, 79, 70, ['地'], '不移', [], '埋在土地里露出上半截，就像是石碑一样。通过扫描分析它所散发的波动，能窥见一点点王国百年前的历史。'],
    "咔咔羽毛":[58, 68, 66, 61, 53, 72, ['翼', '普通'], '咔咔冲刺', [], '跑得很快，手短且柔软，一般用尾巴来代替手的作用。尝试助跑之后短暂地浮空，但似乎一直没能学会飞翔。'],
    "咔咔雀":[78, 91, 88, 81, 71, 96, ['翼', '普通'], '咔咔冲刺', [], '仿照洛克号的帆进化出了大尾巴，曾经尝试练习滑翔，大尾巴让它们能够短暂浮空，也可以用来吓唬和拍打敌人。'],
    "咔咔鸟":[97, 114, 110, 101, 89, 120, ['翼', '普通'], '咔咔冲刺', [], '拥有两条漂亮的大尾巴，虽然无法飞翔，但是抓着大尾巴可以滑翔一段距离，滑翔时身体散发出香香的味道，是因为这个种族普遍有些恐高，紧张的时候会释放舒缓神经的信息素，为自己壮胆。'],
    "小草虫":[73, 40, 43, 50, 57, 60, ['虫', '草'], '花精灵', [], '果树分叉越多的地方，越容易找到他们，常常被误认为是未熟的青葡萄。肤表黏糊糊的，睡觉时缩成一团挂在树上。常观察到许多只挤在一起，目前推测是畏寒的原因。'],
    "草衣虫":[97, 53, 57, 67, 75, 80, ['虫', '草'], '花精灵', [], '与果树是互利共生关系，在果树之间采蜜的同时完成授粉。尾部的花朵是虹吸式进食器官，能够用来吸取和储存花粉，是访花昆虫中最重要的种群。'],
    "花衣蝶":[122, 67, 72, 84, 94, 100, ['虫', '草'], '花精灵', [], '原本的尾巴脱落后变成手中的花朵，似乎蕴含着魔法能量，能当作魔杖使用。冬日寒冷的雨夜里，成千上万的花衣蝶聚集在枯树上休息，清晨又四散飞走，如同花开一夜的蜃景。'],
    "绿翼鸟":[52, 68, 20, 56, 53, 81, ['萌', '翼'], '自由飘', [], '胆小谨慎的精灵，总是下意识地遮挡和隐藏自己。头部心型冠的原理不明，要小心对待，拉扯后，绿翼鸟的性格和样貌会大变，拉扯三次后变回本来的性格和样貌。'],
    "魔翼鸟":[70, 91, 27, 75, 70, 108, ['萌', '翼'], '自由飘', [], '巨大的翅膀能够给予敌人强有力的打击，旋转时更能提高打击效率。物理攻击和魔法攻击都很擅长，翅膀中蕴含着巨量魔力，翅膀内侧的脉络中是魔力流转的痕迹。'],
    "魔眷鸟":[87, 113, 34, 94, 88, 135, ['萌', '翼'], '自由飘', [], '似乎并非是自然产生的物种，对魔法的共鸣极强。根据调查统计结果来看，即使是野生的魔眷鸟也曾经有过契约者，怀疑是被制作出之后再放生的。'],
    "阿米亚特":[64, 95, 47, 67, 42, 45, ['地'], '石头大餐', [], '全身都是岩石，但是眼睛周围没有岩石保护，是十分脆弱的柔软皮肤。喜欢吃不同口味的矿石，总是静静呆着，没什么存在感。'],
    "阿米樱":[86, 127, 62, 89, 56, 60, ['地'], '石头大餐', [], '石头组成的上身和双臂异常粗壮，腿部短小，经常会腿痛。重重挥拳的时候会把构成手部的石头都打散，不过很快就会用岩石修补好。'],
    "罗隐":[107, 159, 78, 112, 70, 75, ['地', '恶'], '石头大餐', [], '身体中结晶脉络光滑透亮，十分坚硬，似乎是某种矿石。长着凶狠的样貌，揣着不知如何表达的善意，示好的时候会展示一下由石头构成的肌肉。'],
    "风铃鲨":[54, 46, 46, 63, 63, 75, ['水', '翼'], '水翼推进', [], '如果看见它们在水面上大量聚集，往往预示着快要下雨。它们的尾巴摆动时带起细小涟漪，薄膜边缘会在气流中轻轻振动，发出清亮悦耳的声响。'],
    "蓝蝶鲨":[72, 61, 61, 84, 84, 100, ['水', '翼'], '水翼推进', [], '它的身体构造至今难以完全解释：体内几乎都是水，身体被一层透明的膜包裹住，里面的液体非常轻。飞行时，由于压力变化或者风势太大，液体有时会漏出来。'],
    "彩蝶鲨":[90, 77, 77, 105, 105, 125, ['水', '翼'], '水翼推进', [], '常被目击从水面贴风飞过，轻盈得几乎不留波纹，它飞行时会借气流而动，并且发出清亮的声音。危险逼近时，它会迅速褪淡体色，降低存在感，再沿风向逃跑。'],
    "石石":[76, 79, 79, 101, 56, 76, ['地'], '石天平', [], '古老的种族，似乎和现在的精灵们很少交流，但对洛克族十分友好。地系部族掌握建造之术后的创造的第一个物种。在古代也被用作计量单位，一个石石约等于三十千克。'],
    "巨灵石":[95, 99, 99, 126, 70, 95, ['地', '幽'], '石天平', [], '从大地获取强大的能量，可以使用地系魔法操纵土壤石头。常常收集一些土壤，石块作为零食，喜欢边讲故事边嚼石头，洛克族的孩子们偶尔会躲在旁边偷偷听它们讲故事。'],
    "仪使者":[64, 54, 57, 69, 71, 51, ['地', '幻'], '观星', [], '在很久很久前被洛克族在遗迹的深处发现，可能已经有上千年的历史了。它的身体由宝石和贵重的金属组成，是被追求财富的人争抢的对象。'],
    "仪式之星":[85, 72, 76, 92, 95, 68, ['地', '幻'], '观星', [], '曾被误认为是雕像，但却有意识和情绪。传说它的身体上镶嵌的宝石象征三种元素。被认为是完美平衡的象征，有研究证明它能够感知或预测时间的流动。'],
    "仪式巨像":[106, 90, 95, 115, 119, 85, ['地', '幻'], '观星', [], '经过时间的洗礼，有些残缺的痕迹，是谜一般的存在，与其相关的研究记录十分少。但相反的这个种族似乎对洛克族十分了解和亲近。“也许生命会消失，从人们的记忆中淡忘，但文明的传承不会断绝。”'],
    "小独角兽":[79, 48, 129, 62, 74, 84, ['光'], '目空', [], '漂亮柔软的绿色鬃毛，让谁看了都想抚摸一下。不知是不是它散发出的魔力的缘故，在它的身边会感觉心灵也变得纯净了。'],
    "白金独角兽":[99, 61, 161, 77, 92, 105, ['光'], '目空', [], '在黑暗中能够照亮周围，像神明一般圣洁而华丽。头顶的角除了穿刺敌人，还能施放出让人震撼的强大魔法冲击。'],
    "旋叶虫":[56, 15, 65, 63, 55, 72, ['普通', '虫'], '共鸣', [], '常挂在树上栖息，不仔细观察的话很难发现它们的踪迹。以类似树叶而闻名，颜色、形状，叶脉、叶梗，甚至是破损处也都非常相似。白天多保持静止，风起时会轻微摇晃，让自己更像一片真的叶子。'],
    "蓬叶虫":[74, 19, 87, 84, 73, 96, ['普通', '虫'], '共鸣', [], '必要时能借助鞘翅短暂地在空中滑行，从一处树冠滑到另一处枝丫。它经常在风力带动下被动迁移，偶尔被风刮走很远，落稳后呆住好一会才能意识到周围环境已经变了。'],
    "风滚暮虫":[93, 24, 109, 105, 91, 120, ['普通', '虫'], '共鸣', [], '借风而行的精灵，利用风把自己带离原地，遇到水面或湿润区域就停下来休息。滚动的时候可以帮助植物传播种子。性情温和，对精灵的幼年体都照顾有加，因此与不少精灵能维持友好的关系。'],
    "小黑猫":[121, 72, 130, 54, 95, 56, ['普通'], '预警', [], '在白天，小黑猫们经常闭眼休息，揣着手休息，如果冒昧地扒开它们的眼皮，会发现很多时候并没有在睡觉，有一种说法：小黑猫闭眼就是在思考。'],
    "黑猫巫师":[152, 91, 163, 67, 119, 70, ['普通'], '预警', [], '夜晚总是在看星星，长久地观察星空和白天不停地思考，似乎让它们拥有了占卜的能力。偶尔会看到有小洛克拿着可可果去拜托黑猫巫师帮忙预测期末考试题。'],
    "忽幽狸":[78, 87, 84, 84, 56, 104, ['幽', '毒'], '下黑手', [], '忽幽狸的尾巴覆盖着剧毒尖刺，静止时会伪装成灌木枝条。当感知到危险，尾巴会瞬间硬化成防御姿态，刺尖分泌的神经毒素能使猎物肌肉僵直。检测显示，其毒素对草系精灵效果加倍。'],
    "影狸":[97, 109, 105, 105, 70, 130, ['幽', '毒'], '下黑手', [], '总是弓着身子，脊椎特化为毒刺弹射装置，用来发射尾巴上的尖刺。体内另外储存了几十根可再生的空心毒刺，通过弹射加压能以每秒10发的速度喷射。'],
    "多多":[47, 53, 53, 82, 66, 54, ['毒', '地'], '毒牙', [], '头部帽子一样的组织触感舒适，冰凉弹软。受到惊吓的话，会从头部喷射出大量毒液，之后迅速缩起陷入昏厥状态。'],
    "多啦多":[63, 70, 70, 109, 88, 72, ['毒', '地'], '毒牙', [], '头部的粘液组织十分不稳定，情绪激动时甚至会掉落一部分。受到刺激后粘液会挥发到空气中，释放致幻毒素。'],
    "古啦多":[79, 88, 88, 136, 110, 90, ['毒', '地'], '毒牙', [], '头部突起越复杂代表着年龄越大，突起内部充斥剧毒毒液，被一层外套膜包裹起来。遇到危险时，会释放更为强大的致幻毒素，但是并不致命。因此，部分洛克因为想要致幻体验，而专门寻找它们。'],
    "哭哭菇":[74, 38, 41, 30, 60, 36, ['幻'], '吸积盘', [], '成群地栖息在潮湿少光的地域，分泌出来的粘液具有独特的气味，引诱旅人深入密林，吸入过多这种气体便会不停流泪。'],
    "怖须菇":[99, 50, 55, 40, 80, 48, ['幻'], '吸积盘', [], '会将身体埋入土壤中，依靠独特的腺体将吸收的水分转化为带有毒性的黏液，干燥与炎热时，散发的气味微微发酸，闻到会想起悲伤的事情。'],
    "怖哭菇":[124, 63, 69, 50, 100, 60, ['幻'], '吸积盘', [], '长期在暗处生存，双目视觉逐渐退化，演化出了胸前能够探测、储存幻系能量的触手。幻系能量凝聚在菌柄中，赋予了其极强的再生能力，即便是经过火焰的炙烤，依旧能迅速生出饱满的躯体。'],
    "恶魔狼":[115, 114, 45, 91, 63, 120, ['恶'], '悲悯', [], '胸前的毛发非常粗糙，似乎能够起到保护作用。能够在战场上高速地移动，迅猛的前爪攻击十分有力。'],
    "小电企鹅":[75, 45, 101, 59, 87, 100, ['冰', '电'], '超负荷', [], '它们生活在寒冷的水域，会用头顶的晶体吸收空气里的电能量。当能量充足时，晶体表面会浮现细碎的亮纹和电光。偏爱暴雪与打雷的天气，风雪越大、雷声越近，它们越活跃。'],
    "电企鹅":[94, 56, 126, 73, 109, 125, ['冰', '电'], '超负荷', [], '常成群扎堆出现来汲取更充沛的电能量，在寒冷区域居民的传说里，电企鹅大量聚集往往预示极端天气将至，当地还有个习俗——如果遇到雷暴天气，就把电企鹅放在房顶上，可以避免雷电损坏房屋。'],
    "雪豆丁":[97, 104, 47, 83, 62, 36, ['冰'], '打雪仗', [], '出生后被父母放置在雪窝里，进食补充的能量会在冬眠时令身躯快速成长。大手大脚的雪豆丁习惯于翻滚着移动。思维直接，比较容易发脾气，可以抚摸脑袋令其冷静。'],
    "雪蛮人":[130, 139, 63, 111, 83, 48, ['冰'], '打雪仗', [], '上肢沉重却灵活，体表鬃毛格外厚重，兼具保暖与防护的功能。吸收的寒气能够压缩后储存在脊背和额头上，形成坚实有力的冰晶，用以保持平衡和击打对手。'],
    "雪巨人":[162, 174, 79, 139, 104, 60, ['冰'], '打雪仗', [], '雪巨人感官极其敏锐，能感受到天气和气温的微小变化，会在族群的幼崽沉睡时巡逻保护它们。双臂能够撑地进行超远距离跳跃，在雪山里飞速前进，跳跃时在岩石上留下后足形状。'],
    "呼呼猪":[98, 95, 33, 88, 81, 68, ['冰', '地'], '冻土', [], '得益于能够分泌疏水性油脂的皮脂腺，皮毛紧实而油亮，既防水又防寒。四肢短而粗壮，跑起来很快，奔跑时偶尔轻微摆动尾巴用来保持平衡。'],
    "獠牙猪":[123, 119, 41, 110, 101, 85, ['冰', '地'], '冻土', [], '身躯看似圆润，但其实十分健壮灵活，拥有令人意想不到的爆发力，即使在冰天雪地里，也非常有活力。'],
    "雪娃娃":[56, 67, 67, 63, 63, 69, ['冰'], '冰封', [], '它对洛克族异常友好，面对温暖的抚摸和拥抱也从不抗拒。传说它们是最早与洛克建立契约的种族之一，耳朵的轮廓正像星之链在契约双方之间勾勒出的形状。'],
    "冰封怨灵":[75, 90, 90, 84, 84, 92, ['冰'], '冰封', [], '缔结契约的向往更明显，甚至会主动靠近潜在契约者，似乎由冰元素和某种尚不清楚的物质构成，推测这部分来自强烈的信念和精神力，使它们的契约更稳定、也更难被外力改变。'],
    "雪灵":[94, 112, 112, 105, 105, 115, ['冰'], '冰封', [], '只有当契约者死亡的时候才会寻找下一位契约者。假如原契约者活着，但它们必须更换契约者的话，可能会自我了结生命。'],
    "大耳帽兜":[78, 62, 59, 39, 78, 54, ['冰', '萌'], '捉迷藏', [], '全身覆满白色绒毛，能抵御寒冷，仔细观察它们的毛毛分为两种，一种是顺滑纤细的针毛，另一种是又软又密的绒毛。虽然体型小，但却不畏惧寒冷，小小的手爪柔软又温暖。似乎喜欢抱抱。'],
    "帽兜娃娃":[104, 83, 78, 52, 104, 72, ['冰', '萌'], '捉迷藏', [], '头部浓密柔软的绒毛负责锁住热量，形成高效的保暖屏障，减少温度流失，兜帽形态的头部结构也可以有效防风。同种族喜欢聚集在一起，贴着脑袋，发热保暖。可能因为这种地缘因素，它们产生了一些社会性和群居属性。'],
    "雪影娃娃":[130, 103, 98, 66, 130, 90, ['冰', '萌'], '捉迷藏', [], '进化后头部绒毛完全脱落，褪去的绒毛承载着进化前的回忆，被制作成一个毛绒娃娃。毛绒娃娃如果能抵御一个严冬就可以获得生命，过程中需要雪影娃娃的悉心养护。'],
    "权杖-Ⅱ":[82, 84, 78, 109, 109, 60, ['机械'], '机械变式', [], '黄金时代的工匠们曾将占星与炼金并列为同一门学问的两种语言。于是他们以火焰为芯，以螺纹为骨，铸成了权杖。现在只有极少量留存下来。'],
    "权杖-Ⅴ":[103, 105, 97, 136, 136, 75, ['机械'], '机械变式', [], '在充满斗争与冲突的时代中诞生的精灵，背负着工匠们的意志、行动与他们所点燃的第一把火。在诞生之初能向周围的机械精灵发出统一指令，它们能协调队列、分配任务，让贵族看到了机械系精灵无限的可能性。'],
    "灵狐":[69, 52, 52, 50, 64, 60, ['火', '冰'], '灵魂灼伤', [], '鼻子呼出的热热的气可能会灼伤小洛克的手，如果在雪山不小心被冻伤，去拜托灵狐帮忙吹一口热气，冻伤瞬间就会痊愈了。'],
    "九尾狐":[92, 70, 70, 67, 86, 80, ['火', '冰'], '灵魂灼伤', [], '尾巴里储存着强大的魔力，能够释放一种特殊的雪魔法，保护越冬作物免受冻害、消灭土壤中害虫，如果在冬天的农田里看到九尾狐出现，就知道明年一定会丰收。'],
    "尖嘴狐仙":[115, 87, 87, 84, 107, 100, ['火', '冰'], '灵魂灼伤', [], '尖嘴狐仙能通过感知大地的温度变化来预测农时。当它摇着尾巴经过农田时，尾巴扇动的气流会形成特殊的暖湿环流，让田地在寒冷的初春也能保持适宜作物生长的温度。'],
    "里奥":[79, 65, 65, 77, 50, 75, ['翼'], '飓风', [], '有着圆滚滚的身躯，小小的翅膀还无法熟练飞翔，却能和愿力发生共鸣，从而获得力量。“和伙伴在一起的安全感连美食都不能替代。即使有时候像个小跟屁虫也无所谓。”'],
    "灵羽勇士":[105, 87, 87, 102, 66, 100, ['翼'], '飓风', [], '弱小的家伙为了伙伴却愿意勇敢向前！光羽圣殿的门扉悄然开启，沐浴在圣光之力的启迪中，澎湃的力量汹涌而来。“它的思绪已沉醉在无垠的天际中，这片蓝天便是它魂牵梦绕的地方”。'],
    "圣羽翼王":[132, 109, 109, 128, 83, 125, ['翼'], '飓风', [], '庇佑这片纯粹的净土，是拥有强大力量之后背负的使命。从上古壁画中得知尘封的过往，它寻求力量，发自内心地想要保护现在的一切。“张开圣洁的羽翼，为同伴抵挡风雨，便是它心中的圣歌”。'],
    "松仔":[63, 83, 34, 77, 60, 63, ['草', '武'], '野性感官', [], '如果察觉到小洛克踏入森林，它们会把角塞在树杈中间伪装松果，诱使小洛克靠近观察。被林间露水打湿的话它们会结伴去晒太阳，晒太阳的时候会散发香香的味道。'],
    "松叶羊":[84, 111, 46, 102, 80, 84, ['草', '武'], '野性感官', [], '刚刚经历换角，松果模样的角脱落，身上的针叶变得锋利，逐渐觉醒领地意识。换角的过程中不要贸然靠近，不然会被踢出几米远。被踢的时候可以闻到它们身上带着森林中泥土和青草的香味。'],
    "针叶巡林":[105, 139, 57, 128, 100, 105, ['草', '武'], '野性感官', [], '角上覆盖的鳞片脱水后自然开裂成树枝状，在森林中极其灵活地穿梭，极少被洛克持续观测到。它们拥有修长的身体和轻盈的骨骼结构，奔跑迅速。'],
    "小勇狮":[82, 31, 66, 53, 78, 48, ['火', '武'], '圣火骑士', [], '喉咙处有容纳火系魔法的身体结构，在小勇狮身上还不太明显，偶尔能发现它打喷嚏的时候会喷出小火花。'],
    "炽焰狮":[110, 41, 89, 70, 104, 64, ['火', '武'], '圣火骑士', [], '只是咆哮就能点燃空气，附着火系魔法的利爪能撕裂岩石。喉咙处的火囊发育成熟，可以喷吐高温火球，但偶尔会因能量过载而引发小型爆炸。'],
    "炽心勇狮":[137, 51, 111, 88, 130, 80, ['火', '武'], '圣火骑士', [], '是王国不休的守护者，它们拥有永不熄灭的火焰心脏，喷吐的火焰会越烧越烈。传说它曾以单狮之力击退山崩，火焰的温度能融化岩石。虽然性格高傲，但对认可的伙伴极为忠诚。'],
    "水滴蛇":[63, 66, 62, 62, 62, 63, ['水', '武'], '思维之盾', [], '和水滴蛇对上眼神的时候，最好保持礼貌并且尝试解答它们留下的难题，如果拒绝回答或敷衍，往往会招来恶作剧，让你在不知不觉中迷路或错过冒险的宝藏。'],
    "水蛇锁":[84, 88, 83, 83, 83, 84, ['水', '武'], '思维之盾', [], '水蛇锁经常悄悄靠近洛克，没有半点声响。它们不以贪婪著称，也不说谎。它们的目的是汲取你的知识。试试用最珍贵的知识与它交换，或许就能平安离开。'],
    "游蛇魔使":[105, 110, 104, 103, 103, 105, ['水', '武'], '思维之盾', [], '会被聪明的洛克吸引，对知识的崇拜无以复加，愿意用任何自己所拥有的事物来交换知识。它们拥有修长柔软的尾巴，据说尾巴尖端可以打开远古的知识之门。'],
    "公平鸽":[113, 93, 93, 125, 125, 100, ['普通'], '衡量', [], '第一、绝对不放过任何争执！第二、绝对不能因为睡过头晚到现场！第三、绝对要公正裁判！第四、绝对要在被双方驱逐之前做出判决。——《公平鸽的守则》'],
    "小怂猫":[74, 106, 101, 89, 76, 76, ['武'], '威慑', [], '胆量极小的猫科精灵，曾因极少被观测记录，被王国记录为已灭绝的物种。翼膜上的眼状图案可以吓退大多数天敌，遇到敌人会张开双臂一动不动地站着，一直到对方离开或者自己昏厥。'],
    "怒目怂猫":[92, 132, 126, 111, 95, 95, ['武'], '威慑', [], '胸脯处长着结构独特的气囊，能够迅速膨起至数倍大，形状像是血盆大口，可以吓退敌人。想回到正常姿势需要排出胸脯中的气体，排气的时候会发出非常可爱的声音，一般会在没有其他生物看到的时候偷偷排气。'],
    "小狮鹫":[61, 69, 39, 64, 33, 72, ['翼'], '乘风连击', [], '只能勉强顶破头部的壳，剩余的蛋壳会陪伴小狮鹫度过幼年时期，能够保护尚且脆弱的羽毛。流线型的蛋壳构造还能减小风阻，丝毫不会影响行动。'],
    "神圣狮鹫":[82, 92, 51, 86, 44, 96, ['翼'], '乘风连击', [], '悬崖间的风往往更加凶猛，崖间的狮鹫家族在这里锻炼出能抵抗风阻的飞行能力，身上的羽毛多为修长的硬羽而较少绒毛，在乱流里也稳住身形并快速调整航向。'],
    "皇家狮鹫":[102, 116, 64, 107, 55, 120, ['翼'], '乘风连击', [], '为了适应强风阻演化出了流线型的面部长羽，微微压住瞳孔是为了在崖间穿梭时更好地视物。尾羽更加修长，能够有效引导风的流动方向，让飞行更加省力和稳定。'],
    "圆眼蜘蛛":[55, 37, 37, 55, 55, 66, ['虫'], '毒腺', [], '幼体的圆眼蜘蛛并不太能织网捕食，多以青草，树果为食。复眼获取信息范围极大，速度极快，即便是独眼，圆眼蜘蛛获取信息速度远超过洛克族100倍。'],
    "尖角蜘蛛":[74, 49, 49, 73, 73, 88, ['虫', '毒'], '毒腺', [], '各关节覆盖着绒毛，绒毛可以疏水和保暖。在湿滑的雨天也可以自由行走，世界的动态在它们眼里显得很慢，所以大部分尖角蜘蛛都是急性子。'],
    "芋香巨角蛛":[92, 61, 61, 91, 91, 110, ['虫', '毒'], '毒腺', [], '颜色鲜艳美丽，尾部丝囊中的液体有剧毒，织出的蜘蛛网散发异香。依靠体毒和利刺能轻易捕获猎物，从不群居，个体之间都保持一定距离，互不侵犯。'],
    "波波螺":[67, 59, 59, 87, 66, 42, ['地', '水'], '消波块', [], '经常频繁抖动身体，推测是缓解外壳生长带来的不适感。它们常集体排成一列迎向海浪，借助外壳的结构消解冲击。浪头拍来时会张口吸入送上门的食物，连很硬的东西也能消化。'],
    "消波螺":[89, 78, 78, 116, 88, 56, ['地', '水'], '消波块', [], '进化后，外壳生长速度更快，更需要精心维护——它们会定期在岩石上打磨外壳。个体之间还会互相叠在一起摩擦打磨，发出“砰砰”的声响。若较长时间没有打磨，行动会明显变慢。'],
    "嗜波螺":[112, 98, 98, 146, 110, 70, ['地', '水'], '消波块', [], '在海浪冲击下，演化出坚韧的矿物质石柱外壳，是一种非常稳定的消波结构，能把浪涌的力量层层化解。声音在石柱间隙中不断反射产生共鸣，能发出类似海浪的声音。'],
    "菇菇丁":[89, 61, 57, 70, 57, 42, ['地', '草'], '多人宿舍', [], '“你知道吗？菇菇丁早已建立了广阔的地下王国，它们的菌丝体蔓延到整片森林，链接着许多土壤，将沾染了星星魔法碎屑的砂土和木头转化为魔法力量，循环利用，它们才是这片森林的主人！”'],
    "多菇丁":[119, 81, 76, 93, 76, 56, ['地', '草'], '多人宿舍', [], '“又有了新的发现，多菇丁埋地时，是在通过菌丝体往地下传播信号，向其他菇精灵发出指令，它们信号的语言结构和古文字非常相似，也许它们的历史远比洛克以为的要早得多。”'],
    "九幽菇":[149, 102, 95, 116, 95, 70, ['地', '草'], '多人宿舍', [], '“在古老的遗迹中发现了九幽菇的石雕，当时的洛克对九幽菇充满了崇拜，他们会在仪式上围着九幽菇唱歌，并在祭祀的指导下服用其孢子，进入幻觉，企图沟通神明，然而也存在接触它的孢子太久而神志不清的情况，等等，难道我也……”'],
    "斑斑":[71, 90, 90, 71, 80, 92, ['翼'], '逐魂鸟', [], '和噜噜家族是远亲，但几乎从不联系，即使是同种族的斑斑们互相之间也并不亲近。从蛋里孵出来之后就非常独立了，经常迈着毛茸茸的小腿，挥着小小的翅膀巡视领地，十分高傲。'],
    "斑枭":[89, 112, 112, 89, 100, 115, ['翼'], '逐魂鸟', [], '和洛克相交甚少的种族，拥有比较强的野性和攻击性。如果在领地内看到生面孔，可能俯冲下来攻击对方，拥有出色的深度感知能力和夜视能力，即使藏在阴影处也难以逃过它的双眼。'],
    "草头鸭":[92, 79, 24, 66, 50, 92, ['草'], '得寸进尺', [], '眼睛长在两侧，不停地转动，不知道是不是在思考，很难解读它的行为规律。视觉范围有360度，从任何方向接近都会被它发现。'],
    "卷毛鸭":[116, 98, 29, 83, 63, 115, ['草', '武'], '得寸进尺', [], '身形与洛克近似，空洞的目光仿佛若有所思。头顶的毛发十分柔软，自然卷曲，这在鸭精灵中十分少见。'],
    "海豹战士":[72, 91, 87, 89, 62, 80, ['武', '水'], '身经百练', [], '圆润的身躯游得飞快，皮肤非常滑溜，十次抓捕中九次都要被它溜走。喜欢被紧挨着或被挤压着的感觉，经常成群结队地出没，迷路的时候，也会一整群一起迷路。'],
    "海豹船长":[90, 113, 109, 111, 77, 100, ['武', '水'], '身经百练', [], '由聪慧且经验丰富的海豹战士进化而来，拥有极强的领地意识。这一物种对征服由极端的渴望，认为其他精灵都要臣服于它们。会指挥手下的海豹战士战斗。'],
    "号儿鱼":[109, 27, 76, 76, 88, 84, ['水'], '泛音列', [], '拥有中空结构的尾巴，空气和水流过的时候会发出小号一样响亮的声音。非常喜欢社交的生物，经常举办盛大的音乐会，不同的小号精灵会轮流展示自己的音乐才华，创造出令人惊叹的合奏。'],
    "圆号鱼":[136, 34, 95, 95, 110, 105, ['水'], '泛音列', [], '会专门去矿物质丰富的水域，通过吸收矿物质来调整背部结构，达到调音的目的。群居，每天早上起来一齐练声，巨大的合奏声能唤醒周围水域的所有生物，喜欢安静的精灵们不愿意住在它们旁边。'],
    "甜田螺":[68, 61, 64, 49, 74, 54, ['水', '萌'], '守护者', [], '它们进食较少，通过经常睡觉来维持体内养分的平衡。只有在海水退潮时才偶尔会出现在沙滩上，在醒着的时候才会立起来，每天大概只有五分之一的时间是醒着的。'],
    "壳乙螺":[91, 81, 86, 66, 99, 72, ['水', '萌'], '守护者', [], '生活在螺壳里，似乎对壳外面的世界不太关心，多数时间都躲在壳里睡觉，对食物的香味比较敏感，可以用食物引诱出来。'],
    "卡洛儿":[114, 102, 107, 82, 124, 90, ['水', '萌'], '守护者', [], '有些呆，不论交给它们什么东西，都会用心地放进自己的壳里。如果能找到办法和它们交流的话，它可能会从螺壳里拿出意想不到的东西作为礼物。'],
    "棋棋":[72, 100, 36, 70, 56, 100, ['武', '地'], '腾挪', [], '“黄金时代地系部族大多无法运用魔力，但他们有着独特的智慧和精湛的技艺。地系精灵王教他们使用建造之术，地系部族用黑色矿物做出了棋子精灵，用以娱乐。”——《黄金时代的地系工匠们·二》'],
    "棋骑士":[90, 126, 45, 88, 69, 125, ['武', '地'], '腾挪', [], '“棋棋的祖先们曾与地系族人相伴而生，地系部族周围多蛮兽。白天棋棋们陷入沉睡，被当作孩子的玩具，在聚落里四处滚动。夜晚则遵循着古老的指令，纷纷醒来守护着部族，替人们守夜巡逻。”——《黄金时代的地系工匠们·三》'],
    "棋齐垒":[89, 94, 38, 116, 77, 75, ['武', '地'], '保卫', [], '“黑白棋子们有类似铠甲一样的外形，民间传闻中白银骑士团的盔甲就是模仿它们建造的，但也有另外一种说法是地系部族的族人参与了白银骑士团的盔甲制造，真实性都已不可考。”——《黄金时代的地系工匠们·五》'],
    "棋祈督":[126, 87, 87, 90, 72, 85, ['武', '地'], '好象坏象', [], '“黄金时代过去后，棋棋开始了流浪，保护族人的遗痕行为一直在影响着它们，它们会主动寻找人文聚落，试图融入洛克的社会。也有部分出现在野外，这些野生的棋棋手感不如家养棋棋温润，干巴巴的有些粗糙。”——《黄金时代的地系工匠们·八》'],
    "棋绮后":[93, 84, 84, 82, 75, 90, ['武', '地'], '渗透', [], '“最初只有黑色棋子，后来地系工匠意外发现了光之水晶，打造了白色的棋子。黑白子交替轮班，互不相见，却共同守护地系部族。它们换班对峙时，不同棋子有各自的行走规则，逐渐发展成象棋游戏规则的雏形。”——《黄金时代的地系工匠们·四》'],
    "奔波鼠":[72, 37, 93, 67, 90, 92, ['地'], '奔波命', [], '毛色杂乱且粗糙，像是融合了泥土、枯叶的颜色，黑色的眼睛透露出机灵的光。它们背着自己的全部家当，在野外长期流浪，一直在路上，从未到达旅途的终点。有着健壮的身躯，但进攻意愿低，只对闪闪发光的东西兴趣浓厚。'],
    "流浪鼠":[90, 46, 116, 84, 112, 115, ['地'], '奔波命', [], '背后鼓鼓的行囊里是更多捡来的收藏品，闪闪发光的物体对它们有着无与伦比的吸引力。不论是亮晶晶的小石子，闪着微光的菌类，还是洛克不小心遗落的饰品。在劳累之后，它们也会静静地在波光粼粼的水面望着月亮。'],
    "呆小路":[52, 60, 64, 68, 79, 57, ['草', '萌'], '营养液泡', [], '幼年期较长，主要靠嗅闻、聆听和头上的叶子触角获取信息。头顶毛发会散发出爆米花的香味，偶尔引来其他精灵。它们之间用互闻头顶代表问候。'],
    "舞动路路":[69, 80, 86, 91, 105, 76, ['草', '萌'], '营养液泡', [], '每只舞动路路都携带着一颗蛋，经常看到它们用头上的毛发擦拭蛋，那是它们最珍视的一部分。蓬松的毛发下看不到眼睛，主要靠头上的叶片来感受环境，身体非常灵活。'],
    "白发路路":[86, 100, 107, 113, 132, 95, ['草', '萌'], '营养液泡', [], '白色的毛发覆盖手臂和身体，随身携带的蛋散发出爆米花的香味。能从随身携带的蛋中获得勇气和力量，暂时还不清楚是什么原理。'],
    "逗逗":[48, 70, 64, 68, 68, 66, ['萌'], '鼓气', [], '体内充满轻质气体，骨骼与肌肉结构都很轻，因此可以在空中漂浮活动。它通过换气调节气体量与分布，来控制自己上浮或下沉。'],
    "气球猫":[64, 93, 86, 90, 90, 88, ['萌'], '鼓气', [], '外表看起来软萌，但身体其实很结实——长期保持平衡姿态，练出了稳定身体的核心肌肉。暴风雨的时候气球猫们都会紧紧抓着树或灌木，一旦松手便很可能被风吹走。'],
    "梦想三三":[81, 117, 107, 113, 113, 110, ['萌'], '鼓气', [], '咻咻咻！听到“喵呜”一声的小洛克们请立刻拿出课本做好，魔法学院开课了！请牢记以下守则：请勿在课堂上投喂助教，请勿拉扯助教的尾巴，请勿对助教发出“嘬嘬嘬”等不尊敬的声音！'],
    "花怨鳗":[232, 73, 73, 110, 90, 52, ['地', '草'], '铃兰晚钟', [], '它们的身体有趋触性，身躯底部会紧贴赖以生存的土地，这让它们有安全感，尤其喜欢湿润的泥土。三朵花常相互缠绕以保持接触，但也因此容易打结。当它们争执时，会发出连绵的铃声。'],
    "鳗尾兽":[290, 91, 91, 138, 113, 65, ['地', '草'], '铃兰晚钟', [], '它头部几乎没有视力，主要靠嘴感受气流来调整方向，偶尔会在地表横冲直撞。吼叫时会带动口中的吊钟形花朵震动，发出阵阵钟声。它们和同伴间通过这些声响，彼此交流。'],
    "伊雷龙":[90, 73, 152, 55, 79, 72, ['龙'], '嫉妒', [], '幼年的小龙喜欢在雨天调皮捣蛋，充满水分的环境令它们十分活跃，在水里游得飞快，小洛克抓也抓不住它们。'],
    "伊兰龙":[112, 91, 190, 69, 99, 90, ['龙'], '嫉妒', [], '修长的尾鳍在空气中划过会留下水雾的痕迹，水雾持续存在形成云朵。观测显示，伊兰亚龙停留超过半小时的区域，降雨概率提升67%。干旱季节时，它们会主动迁往缺水的农田上空。'],
    "拉特":[67, 80, 80, 62, 78, 100, ['电'], '噼啪！', [], '同伴之间经常会打架，用头或者用拳头对撞。每撞一下都会闪着电光。大多数拉特沉默寡言，但正义感十足，拉特们会出手帮助遇到麻烦的洛克和精灵。'],
    "酷拉":[83, 100, 100, 78, 97, 125, ['电'], '噼啪！', [], '能利用电能量高速移动，偶尔也会发生意外事故与同类相撞，交流时会发出“噼啪噼啪”的声音。'],
    "闪电环":[64, 49, 49, 51, 50, 72, ['电'], '防过载保护', [], '总是一副不开心的样子，面对对手的时候会使出全力攻击，不论所处环境有多么危险，只要没电就会立刻陷入昏睡。'],
    "刺电环":[85, 65, 65, 68, 67, 96, ['电'], '防过载保护', [], '经常三三两两聚集在一起互相充电。情绪也会随着电力在同伴之间传播，群聚在一起容易变得更不开心，靠近后能听到此起彼伏的电流杂音，偶尔还有“呜呜”的声音。'],
    "荆棘电环":[106, 81, 81, 85, 84, 120, ['电'], '防过载保护', [], '总是会发出意义不明的“哔哔”声，似乎使用这种声音诱敌。表情看起来更加痛苦了，仿佛电力在体内循环本身就是一种负担。'],
    "小箱怪":[111, 103, 103, 122, 122, 64, ['机械', '幻'], '虚假宝箱', [], '被当作具有自我意识的宝箱，又因为与宝箱形似，变成了象征宝箱的吉祥物精灵。有些洛克会对着小箱怪祈祷好运，甚至向它投掷洛克贝许愿。'],
    "迷迷箱怪":[138, 129, 129, 153, 153, 80, ['机械', '幻'], '虚假宝箱', [], '它们并不追逐也不恐吓，只是静静地埋伏，等待小洛克伸手想要开宝箱时，才会突然袭击。因此老练的魔法师们会说：“冒险不难，难的是抵达终点时敢不敢伸手。”'],
    "古钟蛇":[85, 63, 63, 64, 91, 80, ['萌', '毒'], '拨浪鼓', [], '通常低伏身体，隐藏在草丛中，只露出尾巴发出咚咚咚的轻响，吸引好奇的精灵过来。其尾部的结构可以在摇晃时发出咚咚的鼓声，据说玄玉岛的洛克以此为灵感，制作出了某种广受欢迎的玩具。'],
    "寒音蛇":[106, 79, 79, 80, 114, 100, ['萌', '毒'], '拨浪鼓', [], '拥有能分泌毒液的特殊腺体，能够通过背部空心管状的骨棘发射毒液，致使猎物晕厥。毒液会散发出腐臭的气味，有精灵或洛克靠近查看味道来源时，会猛然跃起扑击。'],
    "矮脚爬爬":[80, 117, 110, 74, 59, 92, ['虫'], '振奋虫心', [], '足较短，翻倒后很难再顺利站起来。野外发现的矮脚爬爬里面十个有八个正在努力翻身。因为可爱的外表而受到许多小洛克的喜爱，但受惊时会咬人，致使王国只能贴出告示，警告大家不要轻易触碰。'],
    "恶魔红钻":[100, 147, 137, 93, 74, 115, ['虫', '恶'], '振奋虫心', [], '喜欢在洞穴的暗处歇息，会提前布好精细且带有剧毒的网守株待兔。步足末端布满危险的剧毒，尖锐而坚硬的触足既能用作进攻的矛，也能用作防御的盾。'],
    "火尾瓦特":[63, 70, 29, 81, 56, 39, ['火'], '蒸汽膨胀', [], '全身被毛又干燥又粗糙，容易产生静电现象，甚至偶尔冒出火星。它的利爪有可能是打火石，连续抓挠树木的话可能会将树木点燃。'],
    "火尾战士":[84, 94, 39, 108, 74, 52, ['火'], '蒸汽膨胀', [], '经常看到它在磨爪子，磨得发烫了才会停下。在战斗前会加热自己的身体以提升力量，有时甚至会让整个头顶的毛发燃烧起来。'],
    "烈火守护":[105, 117, 49, 135, 93, 65, ['火'], '蒸汽膨胀', [], '在草原上全速奔跑的时候时常引发火灾。毛发蓬松且疏水，毛发内部均能发现未燃尽的火星。被驯服后性情极其温顺。'],
    "里拉鳐":[118, 82, 89, 103, 147, 105, ['水'], '吟游之弦', [], '里拉鳐的体表能够分泌并牵连出细长的粘液，这些粘液对水流变化极其敏感，能帮助它判断水流方向。游动时，水流掠过粘液弦会引发持续振动，发出琴音。一般认为雄性的气孔粘液更少，形成的琴弦更细，因此琴声更清脆明亮。'],
    "海枝枝":[78, 58, 148, 96, 120, 110, ['水', '幽'], '珊瑚骨', [], '以海水中的微小生物为食，捕食时会发出“啵啵”声，身体分泌出美丽的树枝状骨骼，呈现美丽的苍青色。喜欢用不同颜色的海藻打扮自己，代谢时能给海藻提供养分，彼此互利共生。'],
    "多西":[64, 73, 26, 82, 70, 30, ['机械', '地'], '定向精炼', [], '可以通过磁性来悬浮在空中，对影响磁场稳定的东西异常敏感，偶尔会因为磁力吸来一些莫名其妙的小零件。可以通过操纵磁力来造成巨大的破坏，常是电力故障的罪魁祸首。'],
    "库多西":[85, 98, 34, 109, 93, 40, ['机械', '地'], '定向精炼', [], '兼具岩石的稳固与钢铁的坚韧，身上带有厚重的泥土气味，推测是因为习惯在地底休眠所致。能够利用磁场的力量发动攻击，但也会在特殊磁场的影响下动弹不得，因此总是在人烟稀少的地方栖息。'],
    "波多西":[106, 122, 43, 136, 116, 50, ['机械', '地'], '定向精炼', [], '能将钢铁之力积蓄于双爪中，使出蓄力重击，威力十足。以地底的粗矿为食，精炼过的钢铁对它而言似乎有着不同寻常的风味。在它出没的地方，常有铁锅失窃。'],
    "小翼龙":[66, 91, 24, 73, 63, 92, ['龙', '翼'], '暴食', [], '身形圆润可爱，翼膜十分柔软，只能在陆地上漂浮。植食性，最爱啃蕨类于低矮灌木，进食的时候总是呛到，猜测是因为呼吸系统还没有发育完全，需要用嘴巴呼吸。'],
    "翼龙":[83, 114, 31, 91, 79, 115, ['龙', '翼'], '暴食', [], '拥有庞大的身躯，肚子总是鼓鼓的，充满发酵的食物。它有力的双翼和坚韧的躯体仿佛为长途飞行而生，在疾飞时仍能自由呼吸。'],
    "电动长颈鹿":[55, 59, 20, 65, 47, 72, ['电'], '蓄电池', [], '平时几乎不带电，通过尾巴放电，贸然摸尾巴可能会被电晕。听到节拍时，它体表的细微电感会跟着节奏一跳一跳，像在悄悄打拍子。'],
    "奔乐鹿":[73, 79, 27, 86, 63, 96, ['电'], '蓄电池', [], '非常喜欢被抚摸，但要避开头、脚和尾巴。夜间视力很差，通常会睡眠；若必须夜间行动，会消耗能量点亮头顶电球来照明，而电球的明暗也会随听见的节拍起伏。'],
    "爵士鹿":[92, 99, 34, 108, 79, 120, ['电'], '蓄电池', [], '即使在野外遇到也不会贸然攻击，目光对视时会礼貌鞠躬。它能更精细地调整头顶电球的电流强度：既可用于攻击与照明，也可配合节奏稳定输出，进行电疗治疗伤病。'],
    "缇塔":[73, 99, 38, 98, 74, 72, ['机械'], '向心力', [], '总是扫描寻找着什么，明明对洛克抱有极大的好奇，但是因为其机器守则限制，只能和洛克保持在一个不远不近的距离。“既可靠又实用，深得洛克们青睐，是您寻物时的不二之选。”'],
    "声波缇塔":[92, 124, 48, 122, 92, 90, ['机械'], '向心力', [], '长长的机械触手可以更方便地抓取物品，遵守着古老的机器守则，然而其需要寻找的物品，似乎早已消逝在历史中。“更加强大的功能，见到机械，它们会毫不留情地抓过来。见到洛克，也会毫不留情地抓过来。”'],
    "小鹬":[56, 38, 38, 67, 52, 69, ['翼'], '起飞加速', [], '小鹬有着灰白色的羽毛，孱弱的双翼还无法驾驭风的力量，但可以依靠尚为柔软的皮甲结构进行短暂的滑翔。虽然幼小却已经懂得在划过水面时溅起水花，吸引鱼虾露头，有时能收获比自己体型还大的战利品。'],
    "鄙目鹬":[75, 51, 51, 90, 70, 92, ['翼'], '起飞加速', [], '栖息在水边的浅滩，橘色的长脚使得它们非常适合涉水行走，喜欢捕食昆虫和甲壳类动物，其眼神如同寒星般锐利冷峻，会左右轻轻扇动翅膀，溅起阵阵涟漪，模仿弱小生物游动，吸引鱼类前来。'],
    "高脚鹬":[94, 63, 63, 112, 87, 115, ['翼'], '起飞加速', [], '拥有较大的脑容量，是运筹帷幄的猎手，坚硬的帽形结构有良好的散热性，会用巨大的头部和双翅在水面上围出一片阴影，以此吸引喜欢在阴凉处生活的水生生物，静待着来乘凉的鱼虾进入它的捕猎范围。'],
    "脆筒甜甜":[72, 67, 72, 42, 55, 60, ['冰'], '加个雪球', [], '使用淡奶油、蛋黄搅拌加热后，冷冻1000小时以上，有极小概率得到一只香草甜甜。以蛋筒底为支点蹦跶着前行，受到惊吓时会缩到自己的蛋筒里瑟瑟发抖。'],
    "香草甜甜":[96, 90, 95, 56, 74, 80, ['冰'], '加个雪球', [], '香草甜甜一族口感各有不同，头上顶着的果果是身体的一部分，拥有360度的视野。因果果吸收不同能量而演化出不同口感分支，身体散发着浓郁的奶香。'],
    "圣代甜甜":[119, 112, 119, 70, 92, 100, ['冰'], '加个雪球', [], '喜欢群居的团结者，圣代甜甜诞生时就生有两颗冰淇淋球，相生相伴，两颗冰淇淋球口味性格不同却能一直融洽相处。'],
    "刺轮砣":[100, 80, 78, 80, 65, 84, ['毒', '萌'], '耐活王', [], '这种形态的刺轮砣皮肤虽然柔软脆弱，但是已经蕴含着强烈的毒系魔法，即使没有足够强壮的身体，也有办法保护自己。'],
    "月亮砣":[125, 100, 98, 100, 81, 105, ['毒', '萌'], '耐活王', [], '皮肤比矿石还要坚硬，经常在有太阳的时候浮在水面上，晒过太阳之后皮肤表面能够分泌出一种蕴含毒系魔法的物质，但对某些精灵有治愈作用，大约是一种以毒攻毒的手段。'],
    "豆丁鱼":[45, 70, 74, 67, 70, 75, ['水', '龙'], '洄游', [], '总是抿着嘴巴气鼓鼓的样子，实际上不是因为生气了，而是在努力练习游泳，传说它们一族有着龙的血脉，只要努力游泳就可以进化为龙，基于精灵遗传学理论推测是龙系混血的精灵。'],
    "快鳍鱼":[60, 93, 99, 89, 93, 100, ['水', '龙'], '洄游', [], '额部鼓起突出，中空有气囊，可以自由改变前额的形状，推测可能是借着移动内部空气来产生形状上的变化，潜水能力相当强，甚至可以一边在水下灵活旋转一边发出多变的叫声，呼唤着同伴，吟唱着记忆深处关于化龙的古老歌谣。'],
    "龙鱼":[75, 116, 123, 112, 116, 125, ['水', '龙'], '洄游', [], '长鳍长尾，身形纤细流畅，拥有强大的游泳能力和跳跃能力，身体的结构比起鱼更接近龙，证明其拥有少量龙系血脉，尾部的红珠中蕴含着些许龙系能量，可以在跃出水面时发出真正的龙吼。'],
    "胆小鳗鱼":[68, 92, 92, 83, 90, 92, ['电', '水'], '生物电', [], '以强力放电而闻名的精灵，种族中的鳗鱼们似乎对自己的知名度一无所知。常常畏首畏尾，即使是非常弱小的对手，也能令它们战战兢兢。曾有胆小鳗鱼假死晕倒在浅滩上，原因是一只爬爬路过。'],
    "闪电鳗鱼":[85, 115, 115, 104, 112, 115, ['电', '水'], '生物电', [], '不会被自己或同类电到，那是因为电鳗体内的脂肪组织有很好的绝缘作用。几乎全身的肌肉组织都能放电，其生物电能与闪电产生强烈共鸣，某些个体能够定向引雷、身体所能承受的电能最高可达8600000伏。'],
    "翡翠水母":[108, 30, 68, 75, 109, 76, ['水', '毒'], '扩散侵蚀', [], '柔软的精灵，通过收缩身体喷水在水中前进。会使用触手释放毒素，以此麻痹对手，然后将其拖入水中。'],
    "琉璃水母":[134, 37, 85, 93, 136, 95, ['水', '毒'], '扩散侵蚀', [], '身体的触手花纹会随心情变化，游动时非常漂亮。是海边生活的洛克的艺术灵感来源。然而它长长的触手可以释放多种效果的攻击，被它的美丽吸引注意时，可能会陷入危险哦。'],
    "裘洛":[44, 56, 50, 39, 48, 75, ['毒'], '蚀刻', [], '胸口的星星状器官暖烘烘的，天冷的时候裘洛们都会把前爪揣在胸口取暖。曾经有洛克贸然地接触了裘洛的尾巴，皮肤变得红肿疼痛，足足半年之后才好转痊愈。'],
    "裘力":[59, 74, 67, 52, 64, 100, ['毒'], '蚀刻', [], '即便在寒冷的冬天也是独来独往，从不聚在一起取暖，太冷的时候会把脚放在尾巴上。尾巴尖处有两个腺体，危险时能迅速喷射毒液，会用尾巴缠住对手释放毒素的同时使其无法逃走。'],
    "裘卡":[73, 93, 83, 65, 81, 125, ['毒'], '蚀刻', [], '独自活动，高傲而优雅的生物。一生中只选择一只伴侣。据研究表明裘卡的体液都有剧毒，紧张时脚垫会分泌汗液，在地面上留下有剧毒的梅花形汗渍。'],
    "可爱猿":[100, 97, 43, 86, 67, 36, ['火'], '散热', [], '头顶着活跃的微型火山，就连睡觉时也会冒出小烟圈。可别因为体型而小看了它，可爱猿头上流出的熔岩就连钢铁也能融化。'],
    "炽热猿":[133, 130, 57, 115, 89, 48, ['火'], '散热', [], '会从头上喷出烟来彰显气势，普遍好斗。打喷嚏的时候，背上也会跟着喷出巨大的浓烟，还会洒出一些岩浆。'],
    "火焰猿":[167, 162, 72, 143, 111, 60, ['火'], '散热', [], '哪怕是休息的时候，也像沉睡的火山一样危险。岩浆涌动的身体需要经常添加燃料，偶尔会把吃不完的食物丢到头顶的火山口里燃尽。'],
    "布鲁斯":[44, 60, 16, 68, 53, 54, ['冰'], '冰钻', [], '头部开始晶体化，触感冰凉。能缓慢吸收周围热量，使自身温度维持在较低水平。头顶的白色绒球对温度变化很敏锐，能帮助它判断环境冷热。'],
    "雪顶布鲁斯":[58, 81, 22, 91, 70, 72, ['冰'], '冰钻', [], '晶体化结构更稳定，修长的腕足变得更灵活，能细致地打理身体、调整伪装姿态，白色绒球对温差的感知也更敏锐。'],
    "冰钻布鲁斯":[73, 101, 27, 114, 88, 90, ['冰'], '冰钻', [], '会拾取断落的枝桠，并在枝桠表面上喷覆与头部成分相似的晶体化物质，使其变得坚硬冰冷，作为武器使用。'],
    "治愈兔":[67, 28, 73, 60, 76, 54, ['火', '萌'], '仁心', [], '平时生活在灌木丛中，看到洛克的话会因为好奇而主动靠近。据说如果感冒了的小洛克摸摸它的小脚，就会很快康复。'],
    "红丝绒":[90, 38, 98, 80, 101, 72, ['火', '萌'], '仁心', [], '绒毛里储存着温和的火系能量，抱在怀里就像一个小暖炉，身体散发出煎药的香味。它特别喜欢照顾受伤的精灵，会用温暖的鼻息轻轻吹拂伤口，伤口就不痛了。'],
    "红绒十字":[112, 47, 122, 100, 127, 90, ['火', '萌'], '仁心', [], '头顶的十字结构能释放出强效的治愈魔法，轻轻一碰就能缓解肌肉酸痛，伤口也会加速愈合。如果看到受伤的精灵但无法施救的话会流泪不止。'],
    "乌达":[80, 95, 49, 70, 42, 33, ['恶', '火'], '恶魔的晚宴', [], '喜欢藏在头盔里吓唬人，是因为需要吸收尖叫来维持自己的能量。实际上胆子很小，遇到危险会倒地装晕。'],
    "迷你乌":[107, 126, 66, 93, 56, 44, ['恶', '火'], '恶魔的晚宴', [], '吓唬人的能力越来越强。在族群当中，越是擅长吓唬人，就越容易受到同伴的尊重，如果气势弱于对方，就要趴在地上装晕认输。'],
    "乌拉塔":[134, 158, 82, 116, 70, 55, ['恶', '火'], '恶魔的晚宴', [], '在对决中常常使用夸张的姿态让对手退却，体内另一股意志会让它在关键时刻保持一条底线——它并不以伤害为乐，只汲取自己必要的尖叫。尊重对手，十分有礼貌。'],
    "螺旋帕帕":[88, 55, 8, 79, 67, 80, ['机械', '翼'], '翼轴', [], '它们立志成为机械系精灵维修专员，曾有大批战损的机械系精灵奇迹般地恢复健康，排着队回到原来生活的地方，这背后默默付出的正是不起眼的螺旋帕帕。'],
    "帕帕斯卡":[110, 68, 10, 99, 84, 100, ['机械', '翼'], '翼轴', [], '在机械系精灵中非常有声望。曾经制造出帕帕斯卡的洛克许下一个愿望，希望能让机械系精灵有尊严地活着。于是帕帕斯卡们整个种族一直在想办法让机械系精灵过上更体面更开心的生活。'],
    "机械方方":[62, 81, 32, 76, 60, 51, ['机械'], '盲拧', [], '似乎是一种非常古老的机械系造物，用处不详。身体结构精巧，拨弄它头顶的天线，会让它变得十分愉快，甚至能断断续续地播放音乐。“方方正正，顶天立地，做人亦该如此。"'],
    "多彩方方":[82, 108, 43, 101, 80, 68, ['机械'], '盲拧', [], '似乎是一种非常古老的机械系造物，用处不详。热爱社交，尤其喜欢和其他种族的幼体玩耍。喜欢歌唱和舞蹈，但普遍不擅长舞蹈，容易摔倒。'],
    "立方人":[103, 135, 54, 127, 101, 85, ['机械'], '盲拧', [], '能够听懂和使用洛克族语言，了解洛克族的礼仪和社会结构，会模仿洛克族的行为，甚至会与其他个体组建家庭。“勤奋的他，总是不停地前行，心中在默念：每个人努力过都不普通。”'],
    "可立鸡":[65, 79, 79, 55, 52, 66, ['火'], '指挥家', [], '鸡冠有特殊腺体分泌可燃气体，情绪激动时，鸡冠会熊熊燃烧。为了便于警戒，可立鸡会排成一队，由鸡冠火焰最旺盛的个体来带领。'],
    "晕晕鸡":[86, 106, 106, 74, 70, 88, ['火'], '指挥家', [], '成长后学会了控制情绪，维持着绅士风度，为了追求优雅和游刃有余，逐渐更能控制火焰释放。偶尔会因为忍耐过度，大脑变得晕乎乎的。'],
    "绅士鸡":[108, 132, 132, 92, 87, 110, ['火', '武'], '指挥家', [], '充满高尚气度的种群，常把一只手放在身后。手中的羽毛可以喷射火焰，制造独特而优雅的攻击。'],
    "武者鸡":[121, 144, 58, 92, 70, 95, ['火', '武'], '斗技', [], '极其发达健壮的双臂是它们的标志性特征，手部演变为锋利的钙化物质。这一分支舍弃了种族遗传下来的火焰魔法，堂堂正正地用双手和踢腿打败敌人。'],
    "优优":[81, 35, 89, 84, 104, 92, ['地', '光'], '哨兵', [], '白天，它们竖起蓬松的尾巴，在沙地上蹦跳活动。夜里守在洞口放哨，尾尖亮起柔和的暖黄光，并用尾巴轻点地面，把消息无声地传给同伴。'],
    "绒光优优":[101, 43, 111, 105, 130, 115, ['地', '光'], '哨兵', [], '进化后它们仍然毛绒绒、行动更显优雅敏捷。战斗时旋转腾挪如轻快战舞，发光的尾巴拖出一缕光丝带。它们警惕性极高，只需将尾巴贴地，便能感知远处的动静。'],
    "噼啪鸟":[78, 116, 109, 85, 85, 145, ['电', '翼'], '连续负荷', [], '“你知道洛克的头发什么时候会竖起来吗？”“是你妈妈突然闯入你房间的时候？”“是进入了噼啪鸟的电场！我还听到它的吼叫声！幸好我跑得快，差点就被电击了！”“……不过这个发型还挺帅的，下次再试试。”'],
    "深蓝鲸":[129, 40, 115, 119, 135, 50, ['水'], '倾轧', [], '深蓝鲸们喜欢贴着水面游泳，会跳出水面，和来往船只嬉戏，遇到危险时，可以把头部冰柱发射出去。种群之间通过歌声和口哨声交流，不论距离多远，互相之间的声音都能传达到。'],
    "格兰种子":[65, 31, 74, 48, 67, 36, ['草'], '生长', [], '格兰种子可以借助微风悬于空中。总是呆呆地望着对方，其实脑袋里盘算着许多鬼点子。体内花粉不停生长，使它躁动不安，总是忍不住捉弄其他精灵。'],
    "格兰花":[86, 42, 99, 64, 90, 48, ['草'], '生长', [], '格兰花头顶可喷射出具有不同功效的花粉，花粉沾身会致痒。它总是带着些许挑衅的眼神看着对方，似乎有意识地引诱对方来打自己，被打能帮它挠痒痒，而击打它时还会传播其花粉。'],
    "格兰球":[108, 52, 124, 80, 112, 60, ['草'], '生长', [], '格兰球的花瓣持续生长与更替，老化花瓣会化作鳞片般的护甲。护甲上黏附诸多致痒花粉，它们热衷于边笑边蹭其他精灵。但洛克研究学者经观察其表情和动作发现，它们坏笑时鳞片般的护甲会微微张开，让它们更好地传粉。'],
    "地鼠":[66, 71, 31, 61, 42, 66, ['地'], '警惕', [], '有着小巧的身体，敏感的尾巴是它最大的弱点。族群数量庞大，生命力极强，几乎不需要喝水。'],
    "遁鼠":[88, 95, 41, 82, 56, 88, ['地'], '警惕', [], '尾巴上有一层坚固的壳，所以挖洞的时候不必担心身后。耳朵的尖端粗糙而耐脏，把摄取的水分和养分都储存在饱满的大耳朵里。'],
    "遁地鼠":[110, 119, 51, 102, 70, 110, ['地'], '警惕', [], '精力旺盛，时常在烈日下的沙漠里飞奔。能够四脚共用，在地下挖掘复杂的洞系，休息的时候常常躲在地下的洞里。'],
    "墨鱿士":[103, 84, 34, 105, 79, 56, ['幽'], '涂鸦', [], '不同于章鱼精灵，它们因为蕴含幽系能量，皮肤已经褪成苍白的颜色，头足里面藏着墨囊，装着它们收集来的颜料。经常藏在厚厚的画纸中间休息。'],
    "混乱鱿彩":[129, 105, 42, 131, 99, 70, ['幽', '恶'], '涂鸦', [], '体型暴涨，皮肤化作流动的红、蓝、黄三色漩涡，情绪高涨时随时像泼墨般炸开。它用触手当画笔，在空中乱甩墨汁，留下大片狂野的色块。'],
    "秩序鱿墨":[78, 120, 39, 124, 113, 130, ['幽', '萌'], '绝对秩序', [], '身体覆上整齐的黑白方格，触手末端变成细长的金属尺，能把漂浮的墨滴精确切割成等分方块。它从不越界，乐于将墨汁按深浅、冷暖、浓度排成矩阵，精准而冷静。'],
    "小甲虫":[98, 71, 31, 97, 61, 60, ['虫'], '坚韧铠甲', [], '头盔顶部和双手上都有黄色的尖角，锋利而坚硬。听说在它们的世界里，坚硬且粗壮的角是身份地位的象征。'],
    "铠甲虫":[122, 88, 39, 121, 77, 75, ['虫'], '坚韧铠甲', [], '全副武装没有破绽，头顶的巨钳令人生畏。甲壳有些沉重，依然可以飞行。但好处是，厚重的甲壳能够挡住敌人的攻击。'],
    "圣剑侍从":[139, 116, 111, 139, 139, 52, ['机械'], '正位宝剑', [], '黄金时代的工匠们曾将占星与炼金并列为同一门学问的两种语言。于是他们以风为芯，以力量和律法为骨，铸成了圣剑。现在只有极少量留存下来。'],
    "圣剑-X":[174, 144, 139, 173, 173, 65, ['机械'], '正位宝剑', [], '制造者把牺牲和奉献作为圣剑的使命，接下来它的一切行为都是为了实现这个目的，无数十号圣剑就这样留在了从前的时代里。现在黄金时代的风早已停息，暗夜过后也迎来了新生。'],
    "吸泥鸥":[99, 89, 33, 87, 71, 76, ['地', '翼'], '无差别过滤', [], '骨骼天生比较脆，需要经常吸食淤泥，泥巴里面含有它们骨骼所需的物质。如果摄入不足，它们的关节会发炎，走起路来可能容易摔倒。吻部尚未完全发育，偶尔会被泥巴噎住。'],
    "泥吼牙":[124, 112, 41, 109, 88, 95, ['地', '翼'], '无差别过滤', [], '一口就能吞下比自己还重的淤泥，皮肤表面也有了吸收淤泥的能力，淤泥硬壳能有效保护它们脆弱的骨骼。有的时候不小心把小体型的精灵邻居吸到嘴巴里，会赶紧吐出来，连连道歉。偶尔也会用嘴巴载着小型精灵度过泥潭。'],
    "大头骨龙":[96, 109, 40, 84, 65, 48, ['龙', '幽'], '不朽', [], '首次被人发现时，大头古龙在地下岩层中沉睡，并且对现在的世界和精灵社会一无所知。骨架不仅坚硬，而且具有再生能力。即使骨头被打断，也可以在短时间内重新长出。骨质翅膀虽然看起来脆弱，但实际上非常坚韧。'],
    "寂灭骨龙":[120, 137, 50, 104, 81, 60, ['龙', '幽'], '不朽', [], '当被从土层里挖出来的时候，它们正在一无所知地睡觉。别看它们脆弱得好像一脚会散架，但埋了亿万年的矿物硬度堪比钻石。“它总是对着镜子思考，幻想自己当年活着时候的样子。”'],
    "厉毒小萝":[67, 64, 17, 81, 59, 108, ['毒', '恶'], '侵蚀', [], '体味清香，翼下藏有数个腺体，能够发射致洛克晕厥的毒雾。受惊时将双翼展为扇形，倾泻毒雾后迅速逃离。'],
    "厉毒修萝":[84, 80, 21, 101, 74, 135, ['毒', '恶'], '侵蚀', [], '翼上的毒棘带有能够分泌剧毒的腺体，狩猎时常在暗处蹲守观察许久，找到时机后从棘刺中射出毒液使猎物昏迷，再飞速捕获。'],
    "小帕尔":[78, 76, 34, 79, 52, 60, ['恶'], '付给恶魔的赎价', [], '探索欲很强的精灵，会通过摇尾巴的方式表达亲近，尾尖会散发出魔法，但并不能很好地控制，时常伤到自己。'],
    "帕尔萨斯":[104, 102, 46, 105, 70, 80, ['恶'], '付给恶魔的赎价', [], '头顶的独角锋利又坚硬，但不蕴含魔法，脱落下来的独角最早被洛克用来制作匕首。“它眼中看到的都是黑白的，它的世界没有色彩，单一的世界却让它有了执着的信念和忠诚的心。”'],
    "龙息帕尔":[130, 127, 57, 131, 87, 100, ['恶'], '付给恶魔的赎价', [], '在古老的典籍中记载，龙息帕尔和其他恶系精灵的行事风格不同，它们秉持着等价交换的原则，会严格遵守自己缔结的契约。在契约完成前绝不会离开，甚至愿意为此等待漫长的时光。'],
    "毛头小蛛":[85, 80, 27, 93, 79, 88, ['虫', '地'], '扫拖一体', [], '身上的绒毛柔软且密集，表面有微小的鳞片结构来吸附灰尘，喜欢从灰尘中吸食各种魔法粉尘，会追逐星星魔法，并吸食炸开的粉末。遇到洛克时容易惊慌失措，全身颤抖，在刺激下炸毛，身上的灰尘也被抖落，让洛克忍不住打喷嚏。'],
    "捕尘长绒":[106, 100, 34, 116, 99, 110, ['虫', '地'], '扫拖一体', [], '绒毛长而纤细，每个洛克小时候都曾把家里打扫清洁的捕尘长绒当作魔法扫帚骑着玩，然后被家长揍一顿，而家长顺手拿起的武器也是捕尘长绒，但是它们喜欢被洛克需要。'],
    "食尘短绒":[109, 105, 37, 113, 97, 115, ['虫', '地'], '特殊清洁场景', [], '绒毛短而浓密，出没在灰尘多的地方，能够在任何表面爬行，其脚掌上短且蓬松的绒毛在爬行时会产生静电作用，牢牢地黏在物体表面上，吸附灰尘，清理家具的死角。'],
    "画精灵":[61, 32, 78, 56, 72, 72, ['普通'], '灰色肖像', [], '画中世界诞生的精灵，活泼好动，对穿梭魔法的运用不是很熟练，偶尔会被画框卡住。曾经尝试少吃可可果来解决这个问题，后来发现并没有效果。'],
    "画像守护":[81, 42, 104, 75, 96, 96, ['普通'], '灰色肖像', [], '可以熟练地在画中与画外穿梭，十分热心肠，喜欢交朋友，经常为认识的画做保养，轻轻吹走灰尘，灰尘太多可能令它一直打喷嚏。但这并不会成为它们的阻碍。'],
    "画间法师手":[101, 53, 131, 94, 120, 120, ['普通', '幻'], '灰色肖像', [], '能够通过画框跨越时间与空间，沉迷于收集更多的见闻，看见更广阔的世界。在长年累月的穿梭中，曾经认识的画已经褪色，但它从没有停下。'],
    "画间沉铁兽":[100, 160, 67, 100, 76, 105, ['普通', '武'], '变形活画', [], '一种沉默寡言的分支形态，稍微有些粗鲁，比起结识更多的朋友，对它来说更重要的是保护现在朋友们的安全，可能在实施保护中不小心磕到朋友的头。确定了需要保护的对象之后，就不会再四处穿梭。'],
    "书魔虫":[67, 75, 75, 48, 73, 57, ['普通'], '图书守卫者', [], '沉迷于阅读，其力量来源于书本的知识。走路和睡觉时都手不释卷，读的书越多体型变得越大，隔一段时间就要调整绑书带的长度，不然会阻碍它学习新知识。'],
    "书卷守护":[89, 100, 100, 64, 98, 76, ['普通'], '图书守卫者', [], '身上带着书本和油墨的味道，看起来小小的，其实比想象中重很多。常与同伴交换藏书，偶尔遇到疑惑的地方，会用书使劲砸自己的头，希望用这种办法让知识快点进入身体。'],
    "古卷执政官":[111, 125, 125, 80, 122, 95, ['普通', '幻'], '图书守卫者', [], '期末时期的图书馆，每当古卷执政官从书架间缓缓现身，它周围的位置总被围得水泄不通，它的古卷如臂膀般展开，书页无声翻动，精准停在学生们最需要的章节上。“不要抗拒，作业是你和知识之间的契约。”'],
    "古卷匣魔像":[114, 109, 109, 134, 89, 95, ['普通', '武'], '构装契约者', [], '“盗贼撬开了书库的大门，随后就被黑暗中什么沉重的打击在空中划出了一道抛物线。然后落荒而逃，并且拒绝再次到访这里，并且嘴里一直嘟囔着：知识就是力量”——某冒险者叙述他们在魔法学院遭到古卷匣魔像攻击的故事。'],
    "绒绒":[58, 42, 44, 49, 80, 69, ['光', '虫'], '绒粉星光', [], '绒绒多在夜间活动，触角能感知星光，体表覆盖着细密的短绒，能吸附少量蕴含星光的细微粉末。偶尔主动靠近洛克，以柔软的身体轻蹭对方，习性黏人，是温顺的小型毛绒精灵。'],
    "小绒茧":[77, 56, 58, 65, 106, 92, ['光', '虫'], '绒粉星光', [], '体表的短绒进化为蓬松且带有黏性的长绒，能够吸附并储存更多星光粉末，直接触摸的话，会感到轻微刺痛。它们吸附的粉末最终在体内融合，驱动体内组织发生解离和重塑，当能量饱和时，绒毛能爆发出强劲的冲击力。'],
    "绒仙子":[96, 71, 73, 81, 133, 115, ['光', '虫'], '绒粉星光', [], '完全发育成型，翅脉中内部流动着体液，横脉与纵脉交汇处形成规整的星形花纹，蕴含强烈的星光能量。胸节与携粉足极度膨大，布满致密的长绒，能牢牢黏附超多光系魔法粉末，这些粉末正是体液代谢后的产物。'],
    "犀角鸟":[63, 88, 40, 67, 44, 66, ['光'], '月光审判', [], '足部又软又嫩，相当虚弱无力。双眼的视觉暂未发育完全，偶尔被毛发遮挡视野。研究推测其毛发承担了主要感官的功能，在看不清的时候也可以通过毛发的感光功能，早早隐藏好自己。'],
    "光纤兽":[83, 117, 54, 90, 58, 88, ['光'], '月光审判', [], '毛发柔软但有韧性，结构特殊，似乎每一根毛发都能接收和发射光能量。它们可以分辨来自四面八方所有光束的到达时间，比较每个光束抵达的时间，计算其距离和能量。'],
    "疾光千兽":[104, 146, 67, 112, 73, 110, ['光'], '月光审判', [], '在月亮升起来之后活动，某些特定时间会散发出微弱光芒，与某些弱小的夜行生物存在共生关系。光能量在每根毛发中沿“之”字形向身体内部传输，可以完好无损地传输到体内，存储凝结成强大力量。'],
    "果冻":[81, 26, 81, 75, 78, 96, ['水'], '茶多酚', [], '透明而不起眼的精灵，经常在干净的水源被发现。研究发现，果冻精灵可以维护森林、湖泊和山脉的生态平衡，似乎是因为它们能让水变得清澈。'],
    "抹茶布丁":[101, 32, 101, 94, 98, 120, ['水', '草'], '茶多酚', [], '抹茶布丁负责舒缓与修复，它会释放带草本气息的挥发物，闻到这种气味，周围的生物会更容易安定下来。它们对同伴与洛克都很亲近，会抱住洛克身上的细小伤口，通过触碰治愈创伤。'],
    "椰浆布丁":[133, 34, 89, 81, 105, 120, ['水', '冰'], '吉利丁片', [], '椰浆布丁负责降温与保鲜，它能在体表形成一层很薄的冷凝膜，使自身在温暖环境中不易软化变形。它常出现在有人维护的洁净水源附近，并更愿意与洛克共存，阴凉的室内能提高它们的舒适度。'],
    "熔岩布丁":[128, 87, 33, 112, 84, 120, ['水', '火'], '美拉德反应', [], '熔岩布丁负责增温与成熟，它体内的活性物质能促进糖分增多，在丰收季节，洛克常带着它们在可可果林区活动，帮助可可果形成更明显的甜香气味，洛克也常把它们的活跃视作可可果林健康的信号之一。'],
    "星尘虫":[49, 47, 47, 46, 58, 60, ['虫'], '契约的形状', [], '洛克与精灵开始缔结契约的时候诞生的物种。以精灵契约为食，是极其稀少的物种。囫囵吞下咕噜球后，先整个保存在身体里一段时间，非常久之后才能完全消化掉。虽然也能吃其他食物，但很难从中获取养分。'],
    "落星虫":[65, 62, 62, 61, 77, 80, ['虫'], '契约的形状', [], '与精灵缔结契约的形式发生变化，咕噜球的样子世代更替，这一种族的外表也渐渐发生了变化。有人曾经尝试使用特殊咕噜球喂食，虫的形态在数年后发生变化，但实验没有继续下来，猜测是因为资金不足。'],
    "陨星虫":[81, 78, 78, 76, 96, 100, ['虫'], '契约的形状', [], '在这个虫族中存在着森严的等级制度，某些虫有资格吃到更稀有的咕噜球。咕噜球研究科曾经提出过一个实验课题《陨星虫与国王球的对撞实验》，后来课题被取消了，原因不明。'],
    "双灯鱼":[102, 55, 111, 57, 93, 84, ['水', '电'], '对流', [], '头顶的光似乎并不是光系魔法，而是来自于某种寄生在其身上的会发光的细菌，目前不清楚发光细菌的其他特性，即使在水中也必须把头顶的灯伸到水面上。'],
    "利灯鱼":[128, 68, 138, 71, 116, 105, ['水', '电'], '对流', [], '独居生物，个体之间保持距离，互不侵犯。常常自言自语，狂笑乱跳。据研究它们头顶的灯内有百万只以上的发光菌，肉眼很难观察。每只菌似乎都有独立意识，能够和本体进行沟通，甚至还有可能侵蚀本体的脑。'],
    "月牙雪熊":[126, 97, 39, 141, 103, 80, ['冰', '幻'], '月牙雪糕', [], '额前的星星质地不明，触感温热，能够从其中检测到异常的魔力波动。如果星星离开身体太远的话，身体会进入沉睡状态。“虽然它从不去看，但是魔法丢得很准。”'],
    "嗜光嗡嗡":[75, 83, 83, 50, 90, 92, ['恶', '光'], '血型吸引', [], '“经实验发现，它们对日光没有反应，其腹部含有特殊的器官，只对光系能量产生反应。因此，存放光水晶时需派遣光系精灵巡逻，混淆它们的感应。”“光系精灵一同发出抗议，要求王国打击嗜光嗡嗡的狂热跟踪和过分亲近行为。”'],
    "窃光蚊":[93, 104, 104, 63, 113, 115, ['恶', '光'], '血型吸引', [], '在微光沼泽，有不少因为长期触光水晶而琥珀化的精灵，这里面却没有恶名昭著的窃光蚊。这是因为窃光蚊会互相合作，一旦有个体吸收了过多光系能量，其他伙伴就会去吸收，帮助其减少体内的能量浓度。'],
    "柴渣虫":[108, 96, 38, 82, 58, 80, ['火', '草'], '煤渣草', [], '“请避免在秋季携带柴渣虫进入山林，若因未采取防火措施而促成险情，洛克将承担所有责任。”——一则来自魔法部的公告'],
    "燃薪虫":[135, 120, 48, 103, 73, 100, ['火', '草'], '煤渣草', [], '木头已经失去了生命迹象，没有实体的火焰精灵在死去木头的身体里栖息。往往喜欢热闹，洛克族的亲近和合作关系会让他们非常自豪。'],
    "空空颅":[70, 7, 37, 54, 64, 48, ['幽'], '搜刮', [], '夜晚很容易在破旧的空屋见到。力量弱小但长着骇人的面容，会恐吓其他精灵，以此来保护自己。它几乎不依赖视觉，通过感知热量来判断生物的位置与距离。'],
    "夜宿颅":[94, 9, 49, 72, 85, 64, ['幽'], '搜刮', [], '吓退其他精灵以取乐，有人说他们以恐惧为食，但没人考证过真假。看起来像眼睛的部分并没有视觉神经，实际通过感知热量来代替视觉。'],
    "夜枭":[117, 10, 61, 90, 106, 80, ['幽'], '搜刮', [], '充盈着魔力的巨爪十分有力。曾经被夜枭吞下过的生命，虽然躯体看似无碍，灵魂却缺失了一部分。'],
    "粉粉星":[93, 54, 102, 57, 101, 88, ['电', '幻'], '星地善良', [], '身体里流淌着神秘的星光能量，打喷嚏的时候会下星星雨。喜欢聚在一起舞蹈，舞蹈时能看到漂亮的星光在它们周围环绕，推测这是粉粉星们交流的一种方式。'],
    "小皮球":[116, 68, 127, 71, 126, 110, ['电', '幻'], '星地善良', [], '浑身散发着紫色的微光，有时会在夜晚拿出珍藏的星星，为迷途的旅人照亮归途。得益于柔软的身体结构，能够将不稳定的星光能量储存在体内，据说星星的亮度代表着存储能量的强度。'],
    "贝瑟":[79, 46, 78, 51, 98, 33, ['机械', '火'], '贪心算法', [], '拥有坚硬而沉重的外壳，靠石头和木头补充提供能量，在能量短缺的时候会靠睡觉度过。“它是坚硬的，它永远不会破碎。可当你狠心地对待它，它终究会伤心地沉睡。”'],
    "贝加尔":[105, 61, 104, 68, 130, 44, ['机械', '火'], '贪心算法', [], '身体结构十分精巧，能够最高效地利用能源，是某些发热供暖装置的设计原型。但在氧气不足的地方身体会逐渐冷下来进入睡眠状态。“经过了岁月的磨练和沉淀，透露出时光的浑厚。”'],
    "贝古斯":[132, 76, 130, 85, 163, 55, ['机械', '火'], '贪心算法', [], '能够通过头顶的蒸汽猜出贝古斯的心情，对于它们而言，不同的心情需要消耗不同数量的矿石。“它是安静的，像座山一样，守候在这里，亘古不变，然而它又是有生命的，内心之中迸发出无限的生机。”'],
    "粉星仔":[80, 63, 119, 58, 102, 92, ['幻'], '双向光速', [], '习性和语言都与目前所知的任何精灵种族不同，身体轻盈，皮肤柔软但极其有韧性。研究学者偶然拾取到它星星飘下的碎屑，密度极高但质量非常轻，研究发现其材质也不属于卡罗西亚大陆的任何一种已知材质。'],
    "粉耳星兔":[100, 79, 148, 73, 127, 115, ['幻'], '双向光速', [], '踏着流星而来的信使，在洛克族里传闻对着它们说话有概率可以梦想成真。它们总是很着急，在夜幕下如同一道道银针般穿行，谁让这世间的许愿总是太多、太多了呢。'],
    "落陨星兔":[93, 61, 125, 87, 141, 130, ['幻', '幽'], '陨落', [], '“能够在流星上倾听许愿的家伙，总会被认为是善良的吧？嘻嘻，它们可从来没说过会以什么方式实现哦！扭曲的实现也是实现。不愿以他人的理想为自己一生的追求，却也无法逃脱命运的桎梏。那么来吧，向它们许愿吧！”'],
    "布瓜蝌":[91, 84, 35, 81, 55, 96, ['幻'], '张弛有度', [], ''],
    "上岸蛙":[114, 106, 44, 101, 69, 120, ['幻'], '张弛有度', [], ''],
    "火红尾":[67, 56, 129, 70, 89, 100, ['火'], '天通地明', [], ''],
    "雅丹鬃":[83, 70, 162, 88, 111, 125, ['火'], '天通地明', [], '岁首更替，丙午是天地通明的光明之年，传闻雅丹鬃是光明的使者，会在新年的子夜仰首长嘶，声如裂帛，鬃毛化作飞天的流火长带，照得千里沙海通明。此时，万盏红灯同时亮起，仿佛回应烈马奔腾——天地通明，光明永昼。'],
    "春团":[48, 51, 57, 65, 57, 63, ['草'], '系统发育', [], '春天草原上出生的小兔，成群出现，以露水为食。吸收的露水储存在耳囊中，因此散发出浆果和青草的香味。'],
    "春兔":[63, 68, 76, 87, 77, 84, ['草'], '系统发育', [], '耳朵的皮肤呈透明玻璃状，触感柔软，内部可以储藏更多的露水。总是细心地做着准备，可以把自己和身边的同伴都照顾得很好，经常用手中的四叶草为其他精灵同伴遮雨。'],
    "春花兔":[79, 85, 95, 103, 90, 105, ['草'], '系统发育', [], '即使找不到水源，也可以吸收耳朵里储存的大量露水。手中的四叶草变为双枪，能够汲取自然中逸散的草系能量，也能作为媒介释放魔法。经常帮助其他精灵，在某些地方被称为勇者兔兔。'],
    "幽星光":[49, 21, 63, 48, 63, 75, ['幻'], '守望星', [], '夜幕的星光之下，这些奇妙的生灵在观测星空，思考并记录时会发出像唱歌一样的声音。它们就像在歌唱宇宙，赞颂复苏，诉说星河的曼妙与知识的无常。但是非常胆小，每当其他生物出现，它们又会隐身于夜空中。'],
    "曜星光":[65, 28, 84, 64, 84, 100, ['幻', '翼'], '守望星', [], '越来越多的行星汇聚在它们身侧，从星辰的辐照微波中，它们能横跨时间，读出数亿年的知识与奥妙。每当它们转动身体周围的行星，可以改变月相，转变天气，传闻如果有洛克在它们出没的高山附近许愿下流星雨，就会被实现。'],
    "暮星辰":[81, 35, 106, 80, 105, 125, ["幻", "翼"], "守望星",[], '当知识积累到一定程度，曜星光便会和星辰共鸣，化身暮星辰。一颗星辰寂灭，一颗星辰升起。涌起的黑洞已然吞噬了它的心灵。无穷无尽的冰冷与空洞啊——但是它依然在等待，等待初生的行星，等待初生的小小洛克来到它的面前。']
}

